        /// <summary>
        /// Generate random number
        /// </summary>
        /// <returns></returns>
        public string randomno()
        {
            string alphabets = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
            string small_alphabets = "abcdefghijklmnopqrstuvwxyz";
            string numbers = "1234567890";
            string characters = alphabets + small_alphabets + numbers;

            int length = 10;
            string otp = string.Empty;
            for (int i = 0; i < length; i++)
            {
                string character = string.Empty;
                do
                {
                    int index = new Random().Next(0, characters.Length);
                    character = characters.ToCharArray()[index].ToString();
                } while (otp.IndexOf(character) != -1);
                otp += character;
            }
            return otp;
        }

        /// <summary>
        /// Reset configuration custom field
        /// </summary>
        /// <param name="fm"></param>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult ResetCF(FirmConfiguredCustomField fm)
        {
            try
            {
                if (!ModelState.IsValid)
                {
                    return BadRequest(ModelState);
                }
                var ftype = Request.Headers.GetValues("configurationtype").FirstOrDefault();
                var ctype = Convert.ToInt32(ftype);
                var param = controllername + ">ResetCF>param=" + ftype;
                db1.usp_AddAudit(Convert.ToInt32(EventType.CustomField), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.CustomField), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                var db = new LawPracticeEntities();
                var storedtempdata = db.FirmConfiguredCustomFields.Where(x => x.ConfigurationType == ctype && x.Firmid.ToString() == LoggedInUser.FirmId.ToString()).ToList();
                if (storedtempdata != null)
                {
                    foreach (var tempdeletdata in storedtempdata)
                    {
                        db.insertdeleteentrytable(Guid.Parse(tempdeletdata.Id.ToString()), "FirmConfiguredCustomFields", LoggedInUser.FirmId);
                    }
                }
                IEnumerable<FirmConfiguredCustomField> ct = (from c in db.FirmConfiguredCustomFields where c.ConfigurationType == ctype && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() select c).ToList();
                db.FirmConfiguredCustomFields.RemoveRange(ct);
                db.SaveChanges();
                var storedtempdata1 = db.ColMaps.Where(x => x.formid == ctype && x.Firmid.ToString() == LoggedInUser.FirmId.ToString()).ToList();
                if (storedtempdata1 != null)
                {
                    foreach (var tempdeletdata1 in storedtempdata1)
                    {
                        db.insertdeleteentrytable(Guid.Parse(tempdeletdata1.id.ToString()), "ColMap", LoggedInUser.FirmId);
                    }
                }
                IEnumerable<ColMap> ct1 = (from c in db.ColMaps where c.formid.ToString() == ctype.ToString() && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() select c).ToList();
                db.ColMaps.RemoveRange(ct1);
                db.SaveChanges();
                var lead = (from prod in db.LeadLists
                            where prod.Firmid.ToString() == LoggedInUser.FirmId.ToString()
                            select prod).ToList();

                foreach (var de in lead)
                {
                    de.col1 = null;
                    de.col2 = null;
                    de.col3 = null;
                    de.col4 = null;
                    de.col5 = null;
                    de.col6 = null;
                    de.col7 = null;
                    de.col8 = null;
                    de.col9 = null;
                    de.col10 = null;
                    de.col11 = null;
                    de.col12 = null;
                    de.col13 = null;
                    de.col14 = null;
                    de.col15 = null;
                    de.iupdate = 1;
                }
                db.SaveChanges();
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.CustomField), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.CustomField), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
            return Ok();
        }

