        /// <summary>
        /// Save lead call
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult PostSaveLeadCall()
        {
            try
            {
                var db = new LawPracticeEntities();
                var ml = new Tbl_leadCall();
                ml.Firmid = LoggedInUser.FirmId;
                ml.firmuser = LoggedInUser.UserId;
                ml.Details = QueryAES.UrlDecode(HttpContext.Current.Request.Form["calldetails"]);
                ml.Calltype = QueryAES.UrlDecode(HttpContext.Current.Request.Form["calltype"]);
                var tdate = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(QueryAES.UrlDecode(HttpContext.Current.Request.Form["lidsid"])));
                if (tdate != "")
                {
                    ml.leadid = Guid.Parse(tdate);
                }
                ml.date_time = DateTime.Now;
                var param = controllername + ">LoadMatter>Matter>param=" + ml.Firmid + "@" + ml.firmuser + "@" + ml.Details + "@" + ml.Calltype + "@" + tdate;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Lead), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Lead), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                var result = Repository.Matter.saveleadcall(ml);
                return Ok(result);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Lead), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Lead), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

        /// <summary>
        /// Save Call
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [ValidateAntiForgeryToken()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult PostSaveCall()
        {
            try
            {
                var db = new LawPracticeEntities();
                var myList = new List<string>();
                dynamic postedFiledata = "";
                var ml = new AddCallList();
                var httpRequest = HttpContext.Current.Request;
                if (httpRequest.Files.Count > 0)
                {
                    var docfiles = new List<string>();
                    string folderPath = HttpContext.Current.Server.MapPath("~/Documents/Calldocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/");
                    string folderpathazure = "Documents/Calldocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId;
                    if (!Directory.Exists(folderPath))
                    {
                        Directory.CreateDirectory(folderPath);
                    }
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
