        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult RemoveTimeEntry(string[] typeIds)
        {
            try
            {
                var db = new LawPracticeEntities();
                var param = controllername + ">RemoveTimeEntry>removetimeentry>param=" + typeIds + "@" + LoggedInUser.FirmId;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                foreach (string did1 in typeIds)
                {
                    string did = "";
                    try
                    {
                        did = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(did1));
                    }
                    catch
                    {
                        did = did1;
                    }
                    var timerdata = db.TimerLists.Where(x => x.Id.ToString() == did).FirstOrDefault();

                    var matterdata = db.AddLawMatterLists.Where(x => x.Id.ToString() == timerdata.tmatter.ToString() && x.Firmid == LoggedInUser.FirmId).FirstOrDefault();
                    if (matterdata != null)
                    {
                        string notification = "You have Deleted Time Entry for Matter - " + matterdata.mname;
                        db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Delete Time Entry", null, did.ToString());
                    }
                    else
                    {
                    }
                }
                var count = Repository.Matter.removetimeentry(typeIds, LoggedInUser.FirmId.ToString());

                db.saveuseractivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), LoggedInUser.UserId.ToString(), 1, DateTime.Now.ToString(), "deletetimer", Guid.Empty.ToString(), null, null, DateTime.Now.ToString());

                return Ok(count);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }
