        /// <summary>
        /// Create File
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult Createfile()
        {
            try
            {
                var fpermissions = QueryAES.UrlDecode(HttpContext.Current.Request.Form["selectedpermission"]);
                var filedetail = QueryAES.UrlDecode(HttpContext.Current.Request.Form["details"]);
                if (filedetail == "")
                {
                    filedetail = null;
                }
                string folderdirectid = "";
                string newpath = "";
                var path = "";
                var directname = QueryAES.UrlDecode(HttpContext.Current.Request.Form["dirname"]);
                string folderdirectidtemp = directname;
                if (folderdirectidtemp == "")
                {
                    path = HttpContext.Current.Server.MapPath("~/WorkSpace/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId);
                    if (!(Directory.Exists(path)))
                    {
                        Directory.CreateDirectory(path);
                    }
                    newpath = "/WorkSpace/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId;
                    var newpathcheck = "WorkSpace/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId;
                    var db = new LawPracticeEntities();
                    ViewFile vf = new ViewFile();
                    var chckdir = db.ViewFiles.Where(x => x.fname == newpathcheck).FirstOrDefault();
                    if (chckdir == null)
                    {
                    }
                    else
                    {
                        directname = chckdir.Id.ToString();
                    }
                }
                else
                {
                    var db = new LawPracticeEntities();
                    var dirname = folderdirectidtemp;
                    if (dirname != null)
                    {
                        folderdirectid = folderdirectidtemp;
                        var fid = LoggedInUser.FirmId;
                        var uid = LoggedInUser.UserId;
                        var dirfullpath = db.sp_Getfilepaths(fid, uid, Guid.Parse(folderdirectid)).FirstOrDefault();
                        string dirpathname = dirfullpath.ToString();
                        newpath = "/WorkSpace/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + dirpathname;
                    }
                    else
                    {
                        newpath = "/WorkSpace/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId;
                    }
                }
                var newfilename = "";
                var newfilenames = "";
                var httpRequest = HttpContext.Current.Request;
                if (httpRequest.Files.Count > 0)
                {
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var docfiles = new List<string>();
                        var postedFile = httpRequest.Files[i];
                        string extension = Path.GetExtension(postedFile.FileName);
                        string pathName = Path.GetDirectoryName(postedFile.FileName);
                        newfilename = "_E2bdADS__" + postedFile.FileName;
                        string origininalfilename = postedFile.FileName;
                        string fileNameOnly = Path.Combine(pathName, Path.GetFileNameWithoutExtension(newfilename));
                        string orfileNameOnly = Path.Combine(pathName, Path.GetFileNameWithoutExtension(origininalfilename));
                        int it = 0;

                        // If the file exists, keep trying until it doesn't
                        while (File.Exists(HttpContext.Current.Server.MapPath("~/" + newpath + "/" + origininalfilename)))
                        {
                            it += 1;
                            origininalfilename = string.Format("{0}({1}){2}", orfileNameOnly, it, extension);
                        }
                        var filePath = HttpContext.Current.Server.MapPath("~/" + newpath + "/" + newfilename);
                        postedFile.SaveAs(filePath);
                        docfiles.Add(filePath);
                        string input = filePath;
                        string output = HttpContext.Current.Server.MapPath("~/" + newpath + "/" + origininalfilename);
                        QueryAES.FileEncrypt(input, output);
                        //delete file
                        System.IO.File.Delete(input);

                        var fileext = Path.GetExtension(newfilename);
                        var data = Repository.Matter.Createfile(origininalfilename, fpermissions, filedetail, directname, fileext, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                        var param = controllername + ">Createfile>Createfile>param=" + newfilename + "@" + fpermissions + "@" + filedetail + "@" + directname + "@" + fileext + "@" + LoggedInUser.FirmId + "@" + LoggedInUser.UserId;
                        db1.usp_AddAudit(Convert.ToInt32(EventType.FileDirectory), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.FileDirectory), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");

                    }
                    return Ok(newpath);
                }
                else
                {
                    return Ok("File not found");
                }
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.FileDirectory), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.FileDirectory), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok(ex.Message);
            }
        }

