        /// <summary>
        /// Custom Form Reset 
        /// </summary>
        /// <param name="fm"></param>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult CustomFormResetCF(FirmConfiguredCustomField fm)
        {
            try
            {
                if (!ModelState.IsValid)
                {
                    return BadRequest(ModelState);
                }
                var ftype = Request.Headers.GetValues("configurationtype").FirstOrDefault();
                var ctype = Convert.ToInt32(ftype);
                var formid = Request.Headers.GetValues("formid").FirstOrDefault();
                var param = controllername + ">CustomFormResetCF>param=" + ctype + "@" + formid;
                db1.usp_AddAudit(Convert.ToInt32(EventType.CustomField), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.CustomField), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                var db = new LawPracticeEntities();
                var storedtempdata = db.FirmConfiguredCustomFields.Where(x => x.ConfigurationType == ctype && x.Firmid.ToString() == LoggedInUser.FirmId.ToString() && x.SubConfigurationType == formid).ToList();
                if (storedtempdata != null)
                {
                    foreach (var tempdeletdata in storedtempdata)
                    {
                        db.insertdeleteentrytable(Guid.Parse(tempdeletdata.Id.ToString()), "FirmConfiguredCustomFields", LoggedInUser.FirmId);
                    }
                }
                IEnumerable<FirmConfiguredCustomField> ct = (from c in db.FirmConfiguredCustomFields where c.ConfigurationType == ctype && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() && c.SubConfigurationType == formid select c).ToList();
                db.FirmConfiguredCustomFields.RemoveRange(ct);
                db.SaveChanges();
                var storedtempdata1 = db.CustomFormColMaps.Where(x => x.formid.ToString() == formid.ToString() && x.Firmid.ToString() == LoggedInUser.FirmId.ToString()).ToList();
                if (storedtempdata1 != null)
                {
                    foreach (var tempdeletdata1 in storedtempdata1)
                    {
                        db.insertdeleteentrytable(Guid.Parse(tempdeletdata1.id.ToString()), "CustomFormColMap", LoggedInUser.FirmId);
                    }
                }

                IEnumerable<CustomFormColMap> ct1 = (from c in db.CustomFormColMaps where c.formid.ToString() == formid.ToString() && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() select c).ToList();
                db.CustomFormColMaps.RemoveRange(ct1);
                db.SaveChanges();
                var customform = (from prod in db.SaveCustomFieldDatas
                                  where prod.Firmid.ToString() == LoggedInUser.FirmId.ToString() && prod.formId.ToString() == formid.ToString()
                                  select prod).ToList();

                // modify each objects
                foreach (var de in customform)
                {
                    de.col1 = null;
                    de.col2 = null;
                    de.col3 = null;
                    de.col4 = null;
                    de.col5 = null;
                    de.col6 = null;
                    de.col7 = null;
                    de.col8 = null;
                    de.col9 = null;
                    de.col10 = null;
                    de.col11 = null;
                    de.col12 = null;
                    de.col13 = null;
                    de.col14 = null;
                    de.col15 = null;
                    de.iupdate = 1;
                }
                db.SaveChanges();

                var updateform = (from c in db.FirmCustomForms where c.Id.ToString() == formid.ToString() && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() select c).FirstOrDefault();

                updateform.IsPublished = false;
                db.SaveChanges();
                return Ok();
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.CustomField), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.CustomField), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
