        /// <summary>
        /// Is Directory Empty
        /// </summary>
        /// <param name="directory"></param>
        /// <param name="path"></param>
        /// <returns></returns>
        public static bool IsDirectoryEmpty(DirectoryInfo directory, string path)
        {
            bool tempr = !Directory.EnumerateFiles(path).Any();
            if (tempr == true)
            {
                FileInfo[] files = directory.GetFiles();
                DirectoryInfo[] subdirs = directory.GetDirectories();
                return (files.Length == 0 && subdirs.Length == 0);
            }
            else
            {
                return false;
            }
        }

