        /// <summary>
        /// Log Service
        /// </summary>
        /// <param name="content"></param>
        private void LogService(string content)
        {
            var templogpath = HttpContext.Current.Server.MapPath("//");
            FileStream fs = new FileStream(templogpath + "//MyKaseoffiecSyncLog.txt", FileMode.OpenOrCreate, FileAccess.Write);
            StreamWriter sw = new StreamWriter(fs);
            sw.BaseStream.Seek(0, SeekOrigin.End);
            sw.WriteLine(content);
            sw.Flush();
            sw.Close();
        }

        /// <summary>
        /// Remove directory
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SaveMoveDirectory()
        {
            try
            {
                var db = new LawPracticeEntities();
                var fid = Request.Headers.GetValues("fid").FirstOrDefault();
                string workingfolder = "WorkSpace";
                string fileName = Request.Headers.GetValues("filename").FirstOrDefault();
                var dirid = Request.Headers.GetValues("dirid").FirstOrDefault();
                var filepath = Request.Headers.GetValues("filepath").FirstOrDefault();
                var newdirpath = Request.Headers.GetValues("dirpath").FirstOrDefault();
                var chckowner = db.ViewFiles.Where(x => x.Id.ToString() == fid.ToString()).FirstOrDefault();

                if (chckowner != null)
                {
                    var chkowner1 = chckowner.Firmuser.ToString();
                    if (chkowner1.ToString() == LoggedInUser.UserId.ToString())
                    {
                    }
                    else
                    {
                        return Ok("not valid user");
                    }
                }

                if (dirid.ToString() == "0")
                {
                    dirid = "00000000-0000-0000-0000-000000000000";
                }
                filepath = "/" + workingfolder + "/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + filepath + "/" + fileName;
                string sourcePath = HttpContext.Current.Server.MapPath("~/" + filepath);
                string targetPath = HttpContext.Current.Server.MapPath("~/WorkSpace/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + newdirpath);
                string sourceFile = sourcePath;
                string destFile = Path.Combine(targetPath, fileName);
                var checkassignfile = db.FirmFilePermissions.Where(x => x.FileId.ToString() == fid.ToString()).FirstOrDefault();
                var checkfiledirectory = db.ViewFiles.Where(x => x.Id.ToString() == fid.ToString()).FirstOrDefault();
                if (checkassignfile != null)
                {
                    return Ok("assign");
                }
                if (checkfiledirectory.fpermission == "1")
                {
                    return Ok("Sync");
                }
                else
                {
                    if (!Directory.Exists(targetPath))
                    {
                        Directory.CreateDirectory(targetPath);
                    }
                    try
                    {
                        File.Move(sourceFile, destFile);
                    }
                    catch (Exception er)
                    {
                        return Ok(er.Message);
                    }
                    ViewFile vf = new ViewFile();
                    var data = db.ViewFiles.Where(x => x.Id.ToString() == fid.ToString()).FirstOrDefault();
                    data.pfile = Guid.Parse(dirid);
                    data.iupdate = 1;
                    db.Entry(data).State = EntityState.Modified;
                    var count = db.SaveChanges();
                    var param = controllername + ">SaveMoveDirectory>param=" + fid + "@" + fileName + "@" + dirid + "@" + filepath + "@" + newdirpath;
                    db1.usp_AddAudit(Convert.ToInt32(EventType.FileDirectory), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.FileDirectory), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                    return Ok("1");
                }
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.FileDirectory), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.FileDirectory), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok("Object reference not set to an instance of an object.");
            }
        }

