        /// <summary>
        /// Send Client Login
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SendClientLogin()
        {
            var userid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["ctoken"].ToString());
            if (!string.IsNullOrEmpty(userid))
            {
                userid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(userid));
                var db = new LawPracticeEntities();
                var datauser = db.FirmUsers.Where(x => x.Id.ToString() == userid.ToString() && x.Firmid == LoggedInUser.FirmId).FirstOrDefault();
                if (datauser != null)
                {
                    var password = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(datauser.Password));
                    var body1 = "Dear user You have registered Successfully <br> Your User Id: " + datauser.UserName + " <br>Password: " + password;
                    string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                    string AssignmentSubmittedMailSubject = WebConfigurationManager.AppSettings["RegistrationToAdminSubject"].ToString();
                    string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["RegistrationMailToAdminBody"].ToString();
                    string plainpassword = "";
                    string fullname = "";
                    string subscribername = Convert.ToString(HttpContext.Current.Session["fullusername"]);
                    AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#USERID#", datauser.UserName);
                    AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#PASSWORD#", plainpassword);
                    AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#NAME#", fullname);
                    AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#SubscriberName#", subscribername);
                    try
                    {
                        CommomUtility obj1 = new CommomUtility();
                        obj1.SendEmail(fromemail, datauser.EmailId, "", AssignmentSubmittedMailSubject, AssignmentSubmittedMailBody);
                    }
                    catch (Exception ex)
                    {

                    }
                }
            }
            return Ok("success");
        }

