        /// <summary>
        /// Enabled Client Account
        /// </summary>
        /// <param name="typeIds"></param>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult EnableClient(string[] typeIds)
        {
            try
            {
                var db = new LawPracticeEntities();
                var Clientlimit = "";
                var getusercount = db.usp_GetFirmLimit(LoggedInUser.FirmId.ToString()).FirstOrDefault();
                if (getusercount != null)
                {
                    Clientlimit = getusercount.iClientPortalLimit;
                    if (String.IsNullOrEmpty(Clientlimit))
                    {
                        return Ok("invalid user license");
                    }
                    var ausercount = db.Usp_GetFirmActiveClient(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
                    if (ausercount < Convert.ToInt32(Clientlimit))
                    {
                        var count = Repository.Matter.enableclient(typeIds, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                        db.saveuseractivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), LoggedInUser.UserId.ToString(), 1, DateTime.Now.ToString(), "enclient", Guid.Empty.ToString(), null, null, DateTime.Now.ToString());
                        var param = controllername + ">EnableClient>enableclient>param=" + typeIds + "@" + LoggedInUser.FirmId.ToString();
                        db1.usp_AddAudit(Convert.ToInt32(EventType.Client), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Client), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                        return Ok(count);
                    }
                    else
                    {
                        return Ok("user exceed limit");
                    }
                }
                else
                {
                    return Ok("invalid user license");
                }
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Client), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Client), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

