        /// <summary>
        /// Update timer
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult PostUpdateTimer()
        {
            try
            {
                var db = new LawPracticeEntities();
                var ml = new TimerList();
                ml.Id = Guid.Parse(QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(QueryAES.UrlDecode(HttpContext.Current.Request.Form["id"]))));
                ml.Firmid = LoggedInUser.FirmId;
                ml.userid = LoggedInUser.UserId;
                var type = QueryAES.UrlDecode(HttpContext.Current.Request.Form["type"]);
                var tcontact = QueryAES.UrlDecode(HttpContext.Current.Request.Form["contact"]);
                try
                {
                    tcontact = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(tcontact));
                }
                catch (Exception er)
                {
                }
                if (tcontact == "" || tcontact == null || tcontact == "null")
                {
                    ml.tcontact = Guid.Empty;
                }
                else
                {
                    ml.tcontact = Guid.Parse(tcontact);
                }
                var tmatters = QueryAES.UrlDecode(HttpContext.Current.Request.Form["matter"]);
                if (tmatters == "" || tmatters == null || tmatters == "null")
                {
