                }
                ml.titem = QueryAES.UrlDecode(HttpContext.Current.Request.Form["item"].ToString());
                ml.callDura = QueryAES.UrlDecode(HttpContext.Current.Request.Form["duration"]);
                string newcallvalue = Regex.Replace(ml.callDura.ToString(), "[A-Za-z ]", "");
                ml.callDura = newcallvalue;
                ml.tdetails = QueryAES.UrlDecodeEditor(HttpContext.Current.Request.Form["details"]);
                var tdate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["dt"]);
                if (tdate != "")
                {
                    ml.tdate = Convert.ToDateTime(tdate);
                }
                ml.tbill = bool.Parse(QueryAES.UrlDecode(HttpContext.Current.Request.Form["billable"].ToString()));
                dynamic bby = QueryAES.UrlDecode(HttpContext.Current.Request.Form["billby"]);
                if (bby != "")
                {
                    ml.tbillby = Guid.Parse(QueryAES.UrlDecode(HttpContext.Current.Request.Form["billby"]));
                }
                dynamic hrate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["hrate"]);
                if (hrate != "")
                {
                    ml.hrrate = Convert.ToInt64(QueryAES.UrlDecode(HttpContext.Current.Request.Form["hrate"]));
                }
                dynamic ttotal = QueryAES.UrlDecode(HttpContext.Current.Request.Form["total"]);
                if (ttotal != "")
                {
                    ml.total = Convert.ToInt64(QueryAES.UrlDecode(HttpContext.Current.Request.Form["total"]));
                }
                ml.tprivnotes = QueryAES.UrlDecode(HttpContext.Current.Request.Form["prevnotes"]);
                ml.date_time = DateTime.Now;
                var myList = new List<string>();
                var docfiles = new List<string>();
                var docsize = new List<string>();

                // Add items to the list
                dynamic postedFiledata = "";
                dynamic postedFiledata1 = "";
                var httpRequest = HttpContext.Current.Request;
                var InfectedFilesResult = "";
                var savemykasefileid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["savemykasefileid"]);
                if (savemykasefileid.ToString() == "undefined")
                {
                    savemykasefileid = "";
                }
                // Add items to the list
                //check size of storage
                if (httpRequest.Files.Count > 0 || (!String.IsNullOrEmpty(savemykasefileid)))
                {
                    var doclimit = DocumentQuota.CheckDocumentmanagementFileSize(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                    if (doclimit.ToString() != "Available")
                    {
                        return Ok(new { Result = doclimit, InfectFiles = InfectedFilesResult });
                    }
                }
                if (httpRequest.Files.Count > 0)
                {
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var postedFile = httpRequest.Files[i];
                        DocUploadResult DUResult = new DocUploadResult();
                        DUResult = SaveCommonModulesDocument.UploadDocument(postedFile, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), "TimeEntry", true);
                        myList.Add(DUResult.FileName);
                        docsize.Add(DUResult.FileSize);
                        docfiles.Add(DUResult.EmailFilePath);
                        if (!String.IsNullOrEmpty(DUResult.InfectedFile))
                        {
                            InfectedFilesResult += DUResult.InfectedFile.ToString() + ",";
                        }
                    }
                }
                InfectedFilesResult = InfectedFilesResult.TrimEnd(',');
                var filearrayd = docfiles.ToArray();
                var sendemailpostedFiledata = string.Join(",", filearrayd);
                var filearray = myList.ToArray();
                postedFiledata = string.Join("|", filearray);
                var matterdata = db.sp_MatterSingleDetail(ml.Firmid, ml.tmatter).FirstOrDefault();
                var id = ml.Id;
                var s = postedFiledata;
                if (s != "")
                {
                    string[] values1 = s.Split('|');
                    for (int j = 0; j < values1.Length; j++)
                    {
                        values1[j] = values1[j].Trim();
                        var chkout = db.Usp_SaveMultipleFileMap(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), ml.Id.ToString(), values1[j], "TimeEntry", docsize[j]);
                    }
                }
                if (!String.IsNullOrEmpty(savemykasefileid))
                {
                    //upload docuemnt from mykase server
                    try
                    {
                        var filelist = SaveMykaseDocument.SaveMykaseDocumentToOtherModule(savemykasefileid, "TimeEntry", LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                        if (!String.IsNullOrEmpty(filelist))
                        {
                            string[] values2 = filelist.Split('|');
                            for (int j = 0; j < values2.Length; j++)
                            {
                                values2[j] = values2[j].Trim();
                                var Docsizes = "0";
                                try
                                {
                                    string[] valuessize = savemykasefileid.Split(',');
                                    {
                                        var documentdetails = db.usp_CheckFilefolderCloud(LoggedInUser.FirmId.ToString(), valuessize[j]).FirstOrDefault();
                                        if (documentdetails != null)
                                        {
                                            Docsizes = Convert.ToString(documentdetails.DocSize);
                                        }
                                    }
                                }
                                catch (Exception ex)
                                {
                                }
                                var chkout = db.Usp_SaveMultipleFileMap(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), ml.Id.ToString(), values2[j], "TimeEntry", Docsizes);
                            }
                        }
                    }
                    catch
                    {
                    }
                }
                if (matterdata != null && !String.IsNullOrEmpty(matterdata.mname))
                {
                    string notification = "You have Edited Time Entry for Matter -" + matterdata.mname;
                    db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Edit Time Entry", null, ml.tmatter.ToString());
                }
                else
                {
                    string notification = "You have Edited Time Entry.";
                    db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Edit Time Entry", null, ml.tmatter.ToString());
                }
                var result = Repository.Matter.edittimer(ml, type);
                var param = controllername + ">PostUpdateTimer>edittimer>param=" + ml.Firmid + "@" + ml.userid + "@" + ml.tprivnotes + "@" + ml.total + "@" + ml.tmatter + "@" + ml.titem + "@" + ml.tdetails + "@" + ml.tdate + "@" + ml.tcontact + "@" + ml.tbillby + "@" + ml.tbill + "@" + ml.stime + "@" + ml.hrrate + "@" + ml.etime;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Timer), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Timer), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                return Ok(new { Result = result, InfectFiles = InfectedFilesResult });

            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Timer), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Timer), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
