        /// <summary>
        /// Enable user
        /// </summary>
        /// <param name="typeIds"></param>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult EnableUser(string[] typeIds)
        {
            try
            {
                var db = new LawPracticeEntities();
                var userlimit = "";
                var getusercount = db.usp_GetFirmLimit(LoggedInUser.FirmId.ToString()).FirstOrDefault();
                if (getusercount != null)
                {
                    userlimit = getusercount.iuserlimit;
                    if (!String.IsNullOrEmpty(userlimit))
                    {
                        try
                        {
                            userlimit = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(userlimit));
                        }
                        catch (Exception ex)
                        {
                            return Ok("invalid user license");
                        }
                    }
                    else
                    {
                        return Ok("invalid user license");
                    }
                    var ausercount = db.Usp_GetFirmActiveUser(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();

                    if (ausercount < Convert.ToInt32(userlimit))
                    {

                        var count = Repository.Matter.enableuser(typeIds, LoggedInUser.FirmId.ToString());
                        db.saveuseractivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), LoggedInUser.UserId.ToString(), 1, DateTime.Now.ToString(), "enuser", Guid.Empty.ToString(), null, null, DateTime.Now.ToString());
                        foreach (string did1 in typeIds)
                        {
                            string did = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(did1));
                            string notification = "You have Enabled a User -";
                            db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Enable User", did.ToString(), did.ToString());
                        }
                        var param = controllername + ">EnableUser>enableuser>param=" + typeIds + "@" + LoggedInUser.FirmId.ToString();
                        db1.usp_AddAudit(Convert.ToInt32(EventType.User), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.User), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                        return Ok(count);
                    }
                    else
                    {
                        return Ok("user exceed limit");
                    }
                }
                else
                {
                    return Ok("invalid user license");
                }
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.User), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.User), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

