        /// <summary>
        /// Create File
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult PostSaveCaseFiles()
        {
            try
            {
                var Defaultcasefilesize = ConfigurationManager.AppSettings["filesizecase"];
                var Defaultuserfilesize = ConfigurationManager.AppSettings["filesizecaseuser"];

                decimal NDefaultcasefilesize = Convert.ToInt32(Defaultcasefilesize);
                decimal NDefaultuserfilesize = Convert.ToInt32(Defaultuserfilesize);
                var db = new LawPracticeEntities();

                string caseids = QueryAES.UrlDecode(HttpContext.Current.Request.Form["lidsid"]);
                try
                {
                    caseids = caseids.Replace(" ", "+");
                    caseids = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(caseids));
                }
                catch (Exception er)
                {

                }
                var caseid = Convert.ToInt32(caseids);
                var newfilename = "";
                var newfilenames = "";

                string folderPath = HttpContext.Current.Server.MapPath("~/Documents/CaseDocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/");

                //Check whether Directory (Folder) exists.
                if (!Directory.Exists(folderPath))
                {
                    //If Directory (Folder) does not exists. Create it.
                    Directory.CreateDirectory(folderPath);
                }
                var httpRequest = HttpContext.Current.Request;
                dynamic casesizesum = 0;
                dynamic usersizesum = 0;
                if (httpRequest.Files.Count > 0)
                {
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var postedFile = httpRequest.Files[i];
                        float casesize = postedFile.ContentLength;
                        casesizesum = casesizesum + casesize;
                    }
                }
                if (httpRequest.Files.Count > 0)
                {
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var postedFile = httpRequest.Files[i];
                        float usersize = postedFile.ContentLength;
                        usersizesum = usersizesum + usersize;
                    }
                }
                string firmids = LoggedInUser.FirmId.ToString();
                string userids = LoggedInUser.UserId.ToString();
                var dbcasesize = db.Tbl_CaseFile.Where(x => x.Firmid.ToString() == firmids.ToString() && x.caseid.ToString() == caseid.ToString()).Select(z => new { z.filesize }).Sum(s => s.filesize);
                var dbusersize = db.Tbl_CaseFile.Where(x => x.Firmid.ToString() == firmids.ToString() && x.userid.ToString() == userids.ToString()).Select(z => new { z.filesize }).Sum(s => s.filesize);
                decimal totalusersize = Convert.ToInt32(dbusersize) + Convert.ToInt32(usersizesum);
                decimal totalcasesize = Convert.ToInt32(dbcasesize) + Convert.ToInt32(casesizesum);
                if (totalcasesize > NDefaultcasefilesize)
                {
                    return Ok("caselimitover");
                }
                if (totalusersize > NDefaultuserfilesize)
                {
                    return Ok("userlimitover");
                }
                if (httpRequest.Files.Count > 0)
                {
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var docfiles = new List<string>();
                        var postedFile = httpRequest.Files[i];
                        float size = postedFile.ContentLength;
                        //checked if already esxist
                        string extension = Path.GetExtension(postedFile.FileName);
                        string pathName = Path.GetDirectoryName(postedFile.FileName);
                        newfilename = postedFile.FileName;
                        string fileNameOnly = Path.Combine(pathName, Path.GetFileNameWithoutExtension(newfilename));
                        int it = 0;

                        // If the file exists, keep trying until it doesn't
                        while (File.Exists(HttpContext.Current.Server.MapPath("~/Documents/CaseDocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + newfilename)))
                        {
                            it += 1;
                            newfilename = string.Format("{0}({1}){2}", fileNameOnly, it, extension);
                        }

                        var filePath = HttpContext.Current.Server.MapPath("~/Documents/CaseDocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + newfilename);
                        var fileextchk = Path.GetExtension(postedFile.FileName);
                        var is_valid = SaveCommonModulesDocument.chkValidExtension(fileextchk);
                        postedFile.SaveAs(filePath);
                        docfiles.Add(filePath);
                        var fileext = Path.GetExtension(newfilename);
                        var Newfilename = "/Documents/CaseDocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + newfilename;
                        var data = Repository.Matter.savecasefile(Newfilename, size, caseid.ToString(), firmids.ToString(), userids.ToString());
                        var param = controllername + ">SaveCaseFile>savecasefile>param=" + Newfilename + "@" + size + "@" + caseid + "@" + firmids + "@" + userids;
                        db1.usp_AddAudit(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                    }
                    return Ok("Success");
                }
                else
                {
                    return Ok("File not found");
                }
            }
            catch (Exception ex)
            {

                db1.usp_AddAuditError(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }

        }

