        /// <summary>
        /// Get encryption key
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult TaskEKData()
        {
            var data = QueryAES.AESKEY();
            string myHex = Convert.ToInt64(data).ToString("X");  // Gives you hexadecimal
            byte[] textAsBytes = Encoding.GetEncoding(28591).GetBytes(myHex);
            string sd = Convert.ToBase64String(textAsBytes);
            return Ok(sd);
        }

