        public IHttpActionResult LoadTimerDataByClientIdbyrowid()
        {
            try
            {
                var clientid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["clientid"]);
                clientid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(clientid));
                int pagenum = Convert.ToInt32(QueryAES.UrlDecode(HttpContext.Current.Request.Form["pagenum"]));
                int pagesize = Convert.ToInt32(QueryAES.UrlDecode(HttpContext.Current.Request.Form["pagesize"]));
                var db = new LawPracticeEntities();
                List<GetTimerDetailsByclientidBYRowid_Result> list = new List<GetTimerDetailsByclientidBYRowid_Result>();
                list = db.GetTimerDetailsByclientidBYRowid(LoggedInUser.FirmId, clientid, LoggedInUser.UserId, Convert.ToInt16(LoggedInUser.RoleId), pagenum, pagesize).ToList();
                foreach (var data in list.ToList())
                {
                    GetTimerDetailsByclientidBYRowid_Result newItem = new GetTimerDetailsByclientidBYRowid_Result();
                    if (data.tmatter != null)
                    {
                        newItem.tmatter = Convert.ToBase64String(QueryAES.EncryptAes(data.tmatter.ToString()));
                        list[list.IndexOf(data)].tmatter = newItem.tmatter;
                    }
                    if (!string.IsNullOrEmpty(data.client))
                    {
                        newItem.client = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(data.client.ToString()));
                        list[list.IndexOf(data)].client = newItem.client;
                    }
                    if (!string.IsNullOrEmpty(data.createdby))
                    {
                        newItem.createdby = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(data.createdby.ToString()));
                        list[list.IndexOf(data)].createdby = newItem.createdby;
                    }
                }
                var a = JsonConvert.SerializeObject(list);
                return Ok(a);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Timer), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Timer), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
