        /// <summary>
        /// Case Next Hearing List by ClientId
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult CaseNextHearingListbyClientId()
        {
            try
            {
                
                var db = new LawPracticeEntities();
                string clientid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["token"]);
                clientid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(clientid));
                List<NextHearingClient> nxtclient = new List<NextHearingClient>();
                var matterid = db.AddLawMatterLists.Where(x => x.matterclientid.ToString() == clientid.ToString() && x.Firmid.ToString() == LoggedInUser.FirmId.ToString()).Select(x => new { x.Id }).ToList();
                foreach (var itemid in matterid)
                {
                    var caseid = db.tblUserCasesMapCaseStatusMasters.Where(x => x.MatterID == itemid.Id).Select(x => new { x.UserCaseId }).ToList();
                    if (caseid != null)
                    {
                        foreach (var itemcaseid in caseid)
                        {
                            string constr = ConfigurationManager.ConnectionStrings["db_checksome"].ToString();

                            SqlConnection con = new SqlConnection(constr);

                            SqlCommand com1 = new SqlCommand("sp_GetNextHearingByIdLawPractice", con);
                            com1.CommandType = CommandType.StoredProcedure;
                            com1.Parameters.AddWithValue("@iid", Convert.ToInt32(itemcaseid.UserCaseId));
                            con.Open();
                            SqlDataReader rdr = com1.ExecuteReader();
                            NextHearingClient nxt = new NextHearingClient();
                            while (rdr.Read())
                            {
                                nxt.ID = Convert.ToInt32(itemcaseid.UserCaseId);
                                nxt.casetype = rdr["casetype"].ToString();
                                nxt.vCourt = rdr["vCourt"].ToString();
                                nxt.Nexthearing = rdr["Nexthearing"].ToString();
                                nxt.benchname = rdr["benchname"].ToString();
                                nxtclient.Add(nxt);
                            }
                            con.Close();
                        }
                    }
                }
                var param = controllername + ">CaseNextHearingListbyClientId>CaseNextHearingListbyClientId>param=" + LoggedInUser.FirmId + "@" + clientid;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Message), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Message), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                return Ok(nxtclient.ToList());
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Message), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Message), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

