        /// <summary>
        /// Remove Custom Activity
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult RemoveCustomActivity()
        {
            try
            {
                string id = QueryAES.UrlDecode(HttpContext.Current.Request.Form["id"]);
                id = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(id));
                var param = controllername + ">RemoveCustomActivity>RemoveCustomActivity>param=" + LoggedInUser.FirmId.ToString() + "@" + LoggedInUser.UserId.ToString() + "@" + id;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                var cmatter = Repository.Matter.removeCustomActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), id);
                var ctype = 10;
                var db = new LawPracticeEntities();
                var storedtempdata = db.FirmConfiguredCustomFields.Where(x => x.ConfigurationType == ctype && x.SubConfigurationType.ToString() == id.ToString() && x.Firmid.ToString() == LoggedInUser.FirmId.ToString()).ToList();
                if (storedtempdata != null)
                {
                    foreach (var tempdeletdata in storedtempdata)
                    {
                        db.insertdeleteentrytable(Guid.Parse(tempdeletdata.Id.ToString()), "FirmConfiguredCustomFields", LoggedInUser.FirmId);
                    }
                }
                IEnumerable<FirmConfiguredCustomField> ct = (from c in db.FirmConfiguredCustomFields where c.ConfigurationType == ctype && c.SubConfigurationType.ToString() == id.ToString() && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() select c).ToList();
                db.FirmConfiguredCustomFields.RemoveRange(ct);
                db.SaveChanges();
                var storedtempdata1 = db.CustomActivityColMaps.Where(x => x.formid.ToString() == id.ToString() && x.Firmid.ToString() == LoggedInUser.FirmId.ToString()).ToList();
                if (storedtempdata1 != null)
                {
                    foreach (var tempdeletdata1 in storedtempdata1)
                    {
                        db.insertdeleteentrytable(Guid.Parse(tempdeletdata1.id.ToString()), "CustomActivityColMap", LoggedInUser.FirmId);
                    }
                }
                IEnumerable<CustomActivityColMap> ct1 = (from c in db.CustomActivityColMaps where c.formid.ToString() == id.ToString() && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() select c).ToList();
                db.CustomActivityColMaps.RemoveRange(ct1);
                db.SaveChanges();
                // delete from savecustomactivity data
                var checkcount = db.SaveCustomActivityDatas.Where(x => x.Firmid == LoggedInUser.FirmId && x.formId.ToString() == id.ToString()).ToList();
                if (checkcount != null)
                {
                    foreach (var element in checkcount)
                    {
                        SaveCustomActivityData contact = (from c in db.SaveCustomActivityDatas
                                                          where c.cid.ToString() == element.cid.ToString() && c.Firmid.ToString() == element.Firmid.ToString()
                                                          select c).FirstOrDefault();
                        db.SaveCustomActivityDatas.Remove(contact);
                        db.insertdeleteentrytable(Guid.Parse(element.cid.ToString()), "SaveCustomActivityData", Guid.Parse(element.Firmid.ToString()));
                        IEnumerable<CustomActivityFileMap> ct2 = (from c in db.CustomActivityFileMaps where c.Firmid.ToString() == element.Firmid.ToString() && c.Fileid.ToString() == contact.cid.ToString() select c).ToList();
                        if (ct2.Count() > 0)
                        {
                            db.CustomActivityFileMaps.RemoveRange(ct2);
                            var fileids = db.CustomActivityFileMaps.Where(z => z.Fileid.ToString() == contact.cid.ToString()).FirstOrDefault();
                            if (fileids != null)
                            {
                                db.insertdeleteentrytable(Guid.Parse(fileids.Id.ToString()), "CustomActivityFileMap", Guid.Parse(element.Firmid.ToString()));
                            }
                            db.SaveChanges();
                        }
                        IEnumerable<CustomActivityUserMap> ct3 = (from c in db.CustomActivityUserMaps where c.Firmid.ToString() == element.Firmid.ToString() && c.rowid.ToString() == contact.cid.ToString() select c).ToList();
