        /// <summary>
        /// Reset Password
        /// </summary>
        /// <returns></returns>
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult ResetPassword()
        {
            try
            {
                var db = new LawPracticeEntities();

                var remail = QueryAES.UrlDecode(HttpContext.Current.Request.Form["email"]);
                var forgetuserid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["forgetuserid"]);
                var checkemail = db.usp_CheckEmailPasswordReset(remail.ToString(), forgetuserid.ToString()).FirstOrDefault();
                var getResetMailTime = DataAccessADO.getResetMailTime(forgetuserid);

                if (!string.IsNullOrEmpty(getResetMailTime.ToString()) && getResetMailTime.ToString() != "0")
                {
                    DateTime resetMailTime = Convert.ToDateTime(getResetMailTime);
                    DateTime currentTime = DateTime.Now;

                    double minutesDifference = (currentTime - resetMailTime).TotalMinutes;
                    if (minutesDifference > 2)
                    {
                        if (checkemail != null)
                        {
                            CommomUtility objmail = new CommomUtility();
                            string strsubject = "", strbody = "";
                            string resetlink = "https://" + HttpContext.Current.Request.Url.Host + "/home/createpassword?status=true&token=" + Convert.ToBase64String(QueryAES.EncryptAes(checkemail.EmailId)) + "&ref=" + Convert.ToBase64String(QueryAES.EncryptAes(checkemail.CurrentDateTime.ToString())) + "&refid=" + Convert.ToBase64String(QueryAES.EncryptAes(checkemail.UserName.ToString()));
                            string AssignmentSubmittedMailSubject = WebConfigurationManager.AppSettings["forgetPasswordSubject"].ToString();
                            string bottomlinkref = WebConfigurationManager.AppSettings["bottomlinkref"].ToString();
                            var insertTokenInDB = DataAccessADO.usp_InsertPasswordResetToken(resetlink, forgetuserid.ToString());
                            string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["ForgotPasswordBody"].ToString();
                            AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#USERNAME#", checkemail.UserName.ToString());
                            AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#RESETLINK#", "<p style='word-break: break-all;'><a href='" + resetlink.ToString() + "'>" + resetlink.ToString() + "</a></p>");
                            AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#LINKREF#", bottomlinkref);
                            objmail.SendEmail("contact@mykase.in", remail, "", AssignmentSubmittedMailSubject, AssignmentSubmittedMailBody);
                            return Ok("success");
                        }
                        else
                        {
                            return Ok(false);
                        }
                    }
                    else
                    {
                        return Ok("Please try after 2 minutes");
                    }
                }
                else
                {
                    if (checkemail != null)
                    {
                        CommomUtility objmail = new CommomUtility();
                        string strsubject = "", strbody = "";
                        string resetlink = "https://" + HttpContext.Current.Request.Url.Host + "/home/createpassword?status=true&token=" + Convert.ToBase64String(QueryAES.EncryptAes(checkemail.EmailId)) + "&ref=" + Convert.ToBase64String(QueryAES.EncryptAes(checkemail.CurrentDateTime.ToString())) + "&refid=" + Convert.ToBase64String(QueryAES.EncryptAes(checkemail.UserName.ToString()));
                        string AssignmentSubmittedMailSubject = WebConfigurationManager.AppSettings["forgetPasswordSubject"].ToString();
                        string bottomlinkref = WebConfigurationManager.AppSettings["bottomlinkref"].ToString();
                        var insertTokenInDB = DataAccessADO.usp_InsertPasswordResetToken(resetlink, forgetuserid.ToString());
                        string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["ForgotPasswordBody"].ToString();
                        AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#USERNAME#", checkemail.UserName.ToString());
                        AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#RESETLINK#", "<p style='word-break: break-all;'><a href='" + resetlink.ToString() + "'>" + resetlink.ToString() + "</a></p>");
                        AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#LINKREF#", bottomlinkref);
                        objmail.SendEmail("contact@mykase.in", remail, "", AssignmentSubmittedMailSubject, AssignmentSubmittedMailBody);
                        return Ok("success");
                    }
                    else
                    {
                        return Ok(false);
                    }
                }
                return Ok();
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.CustomField), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.CustomField), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok(ex);
            }
        }

        /// <summary>
        /// Create New Password
        /// </summary>
        /// <returns></returns>
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult CreateNewPassword()
        {
            try
            {
                var usercrpass = "";
                var db = new LawPracticeEntities();
                FirmUser obj = new FirmUser();
                obj.Password = QueryAES.GetHashedCode(QueryAES.UrlDecode(HttpContext.Current.Request.Form["newpass"]));
                obj.Password = obj.Password.Replace("\n", "");
                var tokenemail = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(QueryAES.UrlDecode(HttpContext.Current.Request.Form["token"])));
                var tokenuserid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(QueryAES.UrlDecode(HttpContext.Current.Request.Form["tokenid"])));
                var tokenuserids = (String)tokenuserid;
                var tokenemails = (String)tokenemail;
                var checktoken = db.usp_CheckEmailPasswordReset(tokenemails.ToString(), tokenuserids.ToString()).FirstOrDefault();
                var getIsUsedForUser = DataAccessADO.sp_getIsUsedForUser(tokenuserids);
                if(getIsUsedForUser.ToString() == "true")
                {
                    return Ok("Token Expired!");
                }
                if (checktoken != null)
                {
                    obj.Firmid = Guid.Parse(checktoken.Firmid.ToString());
                    obj.Id = Guid.Parse(checktoken.Id.ToString());
                    obj.UserName = checktoken.Password;
                    var chckoldpass = db1.FirmUsers.Where(x => x.Firmid == obj.Firmid && x.Id == obj.Id).FirstOrDefault();
                    if (chckoldpass != null)
                    {
                        usercrpass = chckoldpass.Password;
                        if (usercrpass.ToString() != obj.UserName.ToString())
                        {
                            return Ok("passwordmismatch");
                        }
                        if (usercrpass.ToString() == obj.Password.ToString())
                        {
                            return Ok("existpassword");
                        }
                        else
                        {
                            var strdetail = Repository.WorkFlowNew.ChangePassword(obj);
                            try
                            {
                                var dataac = Notification.SaveNotifications("PasswordChange", null, obj.Firmid.ToString(), obj.Id.ToString(), obj.Id.ToString(), null);
                                var dataacs = Notification.SendEmail("PasswordChange", null, obj.Firmid.ToString(), obj.Id.ToString(), obj.Id.ToString(), null);
                                var updateIsUsedFlag = DataAccessADO.sp_UpdateIsUsedFlag(tokenuserids);
                            }
                            catch
                            {

                            }
                            var param = controllername + ">CreateNewPassword>ChangePassword>param=" + obj.Password + "@" + obj.UserName + "@" + obj.Firmid + "@" + obj.Id;
                            db1.usp_AddAudit(Convert.ToInt32(EventType.ChangePassowrd), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.ChangePassowrd), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), obj.Id, param, myIP(), GetMacAddress().ToString(), 0, "");
                            return Ok(strdetail);
                        }
                    }
                    else
                    {
                        return Ok("User not registered with us.");
                    }
                }
                else
                {
                    return Ok(false);
                }
            }
            catch (Exception ex)
            {

                db1.usp_AddAuditError(Convert.ToInt32(EventType.ChangePassowrd), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.ChangePassowrd), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

        /// <summary>
