        public IHttpActionResult Knowledgefilepath()
        {
            try
            {
                var db = new LawPracticeEntities();
                var filepath = QueryAES.UrlDecode(HttpContext.Current.Request.Form["filepath"]);
                var path = "";
                var downloadpathnew = "";
                var fileName = "";
                if (!String.IsNullOrEmpty(filepath))
                {
                    var getknowdetails = db.usp_CheckfolderKnowledge(LoggedInUser.FirmId.ToString(), filepath).FirstOrDefault();
                    fileName = getknowdetails.tfile;
                    if (getknowdetails.pfile.ToString() == Guid.Empty.ToString())
                    {
                        downloadpathnew = "Documents/Knowledge/" + getknowdetails.Firmid + "/" + getknowdetails.firmuser;
                    }
                    else
                    {
                        var dirfullpath = db.sp_Getknowfilepaths(Guid.Parse(getknowdetails.Firmid.ToString()), Guid.Parse(getknowdetails.firmuser.ToString()), Guid.Parse(getknowdetails.pfile.ToString())).FirstOrDefault();
                        string dirpathname = dirfullpath.ToString();
                        downloadpathnew = "Documents/Knowledge/" + getknowdetails.Firmid + "/" + getknowdetails.firmuser + "/" + dirpathname;
                    }
                }
                string fakepathin = HttpContext.Current.Server.MapPath("~/azuredirin/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId);
                string fakepathout = HttpContext.Current.Server.MapPath("~/azuredirout/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId);
                if (!Directory.Exists(fakepathin))
                {
                    Directory.CreateDirectory(fakepathin);
                }
                if (!Directory.Exists(fakepathout))
                {
                    Directory.CreateDirectory(fakepathout);
                }
                var source = AzureDocumentself.Dirfilepath(downloadpathnew, fileName, fakepathin, fakepathout, null, null);
                var destination = "/azuredirout/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + fileName;
                return Ok(destination);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.ChangePassowrd), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.ChangePassowrd), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
