        /// <summary>
        /// Directory file path
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult Dirfilepath()
        {
            try
            {
                var db = new LawPracticeEntities();
                var urltypes = QueryAES.UrlDecode(HttpContext.Current.Request.Form["urltypes"]);
                var baseurl = QueryAES.UrlDecode(HttpContext.Current.Request.Form["baseurl"]);
                var filepath = QueryAES.UrlDecode(HttpContext.Current.Request.Form["filepath"]);
                filepath = filepath.Replace(" ", "+");
                filepath = QueryAES.DecryptStringAES(filepath);
                var source = filepath;
                var destination = filepath.ToString().Replace("WorkSpace", "Tempwps/Gdwqus").Replace("LawPractice_ds", "tempwps/Gdwqus");
                var root = destination.Substring(0, destination.LastIndexOf('/'));
                if (!Directory.Exists(HttpContext.Current.Server.MapPath("~/" + root)))
                {
                    Directory.CreateDirectory(HttpContext.Current.Server.MapPath("~/" + root));
                }
                if (File.Exists(HttpContext.Current.Server.MapPath("~/" + source)))
                {
                    try
                    {
                        QueryAES.FileDecrypt(HttpContext.Current.Server.MapPath("~/" + source), HttpContext.Current.Server.MapPath("~/" + destination));
                    }
                    catch (Exception err)
                    {
                    }
                }
                if (urltypes == "office")
                {
                    urltypes = "https://view.officeapps.live.com/op/view.aspx?src=" + baseurl + destination;
                }
                if (urltypes == "docs")
                {
                    urltypes = "https://docs.google.com/gview?url=" + baseurl + destination + "&embedded=true";
                }
                if (urltypes == "dropbox")
                {
                    urltypes = baseurl + destination;
                }
                return Ok(urltypes);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.ChangePassowrd), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.ChangePassowrd), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }


        /// <summary>
        /// Save activity event alerts
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult saveactivityeventalerts()
        {
            try
            {
                var db = new LawPracticeEntities();
                int hearingAlert = 0;
                int alertDays = 0;
                var eventid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace((QueryAES.UrlDecode(HttpContext.Current.Request.Form["eventid"]).ToString().Replace(" ", "+"))));
                var etype = QueryAES.UrlDecode(HttpContext.Current.Request.Form["etype"]);
                var remark = QueryAES.UrlDecode(HttpContext.Current.Request.Form["remark"]);
                var hearingAlert1 = QueryAES.UrlDecode(HttpContext.Current.Request.Form["hearingAlert"]);
                if (hearingAlert1 != "")
                {
                    hearingAlert = Convert.ToInt32(hearingAlert1);
                }
                var alertDays1 = QueryAES.UrlDecode(HttpContext.Current.Request.Form["alertDays"]);
                if (alertDays1 != "")
                {
                    alertDays = Convert.ToInt32(alertDays1);
                }
                var caldate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["caldate"]);
                var hdate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["duedate"]);
                var editalertid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["alertid"]);
                var reminderfor = QueryAES.UrlDecode(HttpContext.Current.Request.Form["reminderfor"]);
                string docs = "";
                int scount = 0;
                string s = "";
                var alertdate = "";
                if (editalertid != "")
                {
                    editalertid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(editalertid.ToString().Replace(" ", "+")));
                    if (caldate == "")
                    {
                        if (hearingAlert == 0)
                        {
                            s = "Please Set Alert Date.";
                        }
                        else if (alertDays == 0 && hearingAlert != 3)
                        {
                            s = "Enter alert days";
                        }
                        if (hearingAlert == 3)
                        {
                            alertdate = hdate;
                        }
                        else
                        {
                            alertdate = Convert.ToDateTime(hdate).AddDays(-alertDays).ToShortDateString();
                        }
                    }
                    else
                    {
                        string date = caldate;
                        string date1 = "";
                        DateTime myDate = DateTime.ParseExact(date, "MM/dd/yyyy", System.Globalization.CultureInfo.InvariantCulture);
                        DateTime myDate1;
                        string day = "";
                        myDate1 = DateTime.Parse(hdate);
                        day = myDate1.ToString("MM/dd/yyyy");
                        if (myDate > myDate1)
                        {
                            TimeSpan ts = myDate - myDate1;
                            alertDays = ts.Days;
                            hearingAlert = 2;
                            return Ok("Alert Date can not be set after due date");
                        }
                        else if (myDate < myDate1)
                        {
                            TimeSpan ts = myDate1 - myDate;
                            alertDays = ts.Days;
                            hearingAlert = 1;
                        }
                        else
                        {
                            alertDays = 0;
                            hearingAlert = 3;
                        }
                        alertdate = caldate;
                    }
                    //edit alert setting data
