        /// <summary>
        /// Save Sync Row Data
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SaveSyncRowData()
        {
            try
            {
                var count = 0;
                int np = 1;
                var fparent = "";
                StringBuilder sb = new StringBuilder();
                sb.Clear();
                string decstring = "";
                var tablecode = QueryAES.UrlDecode(HttpContext.Current.Request.Form["tablekey"]);
                string tokens = QueryAES.UrlDecode(HttpContext.Current.Request.Form["token"]);
                string[] values = tokens.Split(',');
                for (int i = 0; i < values.Length; i++)
                {
                    values[i] = values[i].Trim();
                    if (!string.IsNullOrEmpty(values[i]))
                    {
                        if (tablecode.ToString() != "files")
                        {
                            try
                            {
                                decstring = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(values[i]));
                            }
                            catch
                            {
                                decstring = values[i];
                            }
                        }
                        else
                        {
                            decstring = values[i];
                        }
                        sb.Append(decstring);
                        sb.Append(",");
                    }
                }
                tokens = sb.ToString().TrimEnd(',');
                string ptokens = tokens;
                tokens = tokens.Replace(",", "','");
                var tablenamepkey = "";
                var firmid = LoggedInUser.FirmId.ToString();
                //get primary key and table name
                var gettablename = db1.sp_getsynctablepkey(tablecode).FirstOrDefault();
                if (gettablename != null)
                {
                    tablenamepkey = gettablename.PrimaryKey;
                    //update table row
                    if (gettablename.TableName == "Tbl_FavContact")
                    {
                        tablenamepkey = "ContactId";
                    }
                    if (gettablename.TableName == "RegUser")
                    {
                        tablenamepkey = "LoginId";
                    }
                    if (gettablename.TableName.ToString() == "ViewFiles")
                    {
                        string[] pvalues = ptokens.Split(',');
                        for (int i = 0; i < pvalues.Length; i++)
                        {
                            np = 1;
                            pvalues[i] = pvalues[i].Trim();
                            string newparent = pvalues[i];
                            //find parent
                            while (np > 0)
                            {
                                var getparent = db1.ViewFiles.Where(x => x.Firmid == LoggedInUser.FirmId && x.Id.ToString() == newparent.ToString()).FirstOrDefault();
                                if (getparent != null)
                                {
                                    fparent = getparent.pfile.ToString();
                                    if (fparent.ToString() == Guid.Empty.ToString())//for rrot
                                    {
                                        var counts = db1.usp_updatesyncrow(gettablename.TableName, tablenamepkey, firmid, pvalues[i].ToString());
                                        count = counts;
                                        np = 0;
                                    }
                                    else //not root
                                    {
                                        var setparent = db1.ViewFiles.Where(c => c.Firmid == LoggedInUser.FirmId && c.Id.ToString() == fparent.ToString()).FirstOrDefault();
                                        setparent.IsSync = 1;
                                        setparent.iupload = null;
                                        db1.Entry(setparent).State = EntityState.Modified;
                                        db1.SaveChanges();
                                        newparent = fparent;
                                    }
                                }
                            }
                        }
                    }
                    else
                    {
                        var counts = db1.usp_updatesyncrow(gettablename.TableName, tablenamepkey, firmid, tokens.ToString());
                        count = counts;
                    }
                    return Ok(count);

                }
                else
                {
                    return Ok();
                }
            }
            catch (Exception ex)
            {
                return Ok(ex.Message);
            }
        }

