        /// <summary>
        /// save escilation
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult saveescilation()
        {

            var db = new LawPracticeEntities();
            var user = QueryAES.UrlDecode(HttpContext.Current.Request.Form["user"]);
            var level = QueryAES.UrlDecode(HttpContext.Current.Request.Form["level"]);
            var token = QueryAES.UrlDecode(HttpContext.Current.Request.Form["token"]);
            int hearingAlert = 0;
            int alertDays = 0;
            var caldate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["caldate"]);
            var hearingAlert1 = QueryAES.UrlDecode(HttpContext.Current.Request.Form["hearingAlert"]);
            if (hearingAlert1 != "")
            {
                hearingAlert = Convert.ToInt32(hearingAlert1);
            }
            var alertDays1 = QueryAES.UrlDecode(HttpContext.Current.Request.Form["alertDays"]);
            if (alertDays1 != "")
            {
                alertDays = Convert.ToInt32(alertDays1);
            }
            string s = "";
            try
            {
                token = token.ToString().Replace(" ", "+");
                token = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(token));
            }
            catch (Exception er)
            {

            }
            var getduedate = db.usp_GetTaskDueDateById(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), token).FirstOrDefault();

            if (caldate == "")
            {
                if (hearingAlert == 0)
                {
                    s = "Please Set Alert Date.";
                    return Ok(s);
                }
                else if (alertDays == 0 && hearingAlert != 3)
                {
                    s = "Enter alert days";
                    return Ok(s);
                }
            }
            else
            {
                string date = caldate;
                string date1 = "";
                DateTime myDate = DateTime.ParseExact(date, "MM/dd/yyyy", System.Globalization.CultureInfo.InvariantCulture);

                DateTime myDate1;
                string day = "";

                myDate1 = Convert.ToDateTime(getduedate);
                day = myDate1.ToString("MM/dd/yyyy");

                if (myDate > myDate1)
                {
                    TimeSpan ts = myDate - myDate1;
                    alertDays = ts.Days;
                    hearingAlert = 2;
                }
                else if (myDate < myDate1)
                {
                    TimeSpan ts = myDate1 - myDate;
                    alertDays = ts.Days;
                    hearingAlert = 1;
                }
                else
                {
                    alertDays = 0;
                    hearingAlert = 3;
                }
            }
            int ct = 0;
            if (getduedate != null)
            {
                var eachId1 = user.Split(new[] { "," }, StringSplitOptions.RemoveEmptyEntries).Distinct();
                foreach (var item1 in eachId1)
                {
                    var counts = db.Usp_SaveTaskEsclation(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), token.ToString(), item1, getduedate.ToString(), Convert.ToInt32(level), DateTime.Now.ToShortTimeString(), hearingAlert, alertDays);
                    ct = ct + 1;
                }
            }
            return Ok("success");
        }

