        /// <summary>
        /// Save Notice
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SaveNotice()
        {
            var db = new LawPracticeEntities();
            var nsubject = QueryAES.UrlDecode(HttpContext.Current.Request.Form["nsubject"]);
            var details = QueryAES.UrlDecode(HttpContext.Current.Request.Form["details"]);
            var ndate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["ndate"]);
            var nparty = QueryAES.UrlDecode(HttpContext.Current.Request.Form["nparty"]);
            var aparty = QueryAES.UrlDecode(HttpContext.Current.Request.Form["aparty"]);
            var place = QueryAES.UrlDecode(HttpContext.Current.Request.Form["place"]);
            var noparty = QueryAES.UrlDecode(HttpContext.Current.Request.Form["noparty"]);
            var aoparty = QueryAES.UrlDecode(HttpContext.Current.Request.Form["aoparty"]);
            var userlist = QueryAES.UrlDecode(HttpContext.Current.Request.Form["user"]);
            var token = QueryAES.UrlDecode(HttpContext.Current.Request.Form["token"]);
            if (String.IsNullOrEmpty(token))
            {
                token = Guid.Empty.ToString();
            }
            var myList = new List<string>();
            dynamic postedFiledata = "";
            var httpRequest = HttpContext.Current.Request;
            if (httpRequest.Files.Count > 0)
            {
                var docfiles = new List<string>();
                string folderPath = HttpContext.Current.Server.MapPath("~/Documents/Noticedocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/");
                string folderpathazure = "Documents/Noticedocuments/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId;
                //Check whether Directory (Folder) exists.
                if (!Directory.Exists(folderPath))
                {
                    //If Directory (Folder) does not exists. Create it.
                    Directory.CreateDirectory(folderPath);
                }
                for (int i = 0; i < httpRequest.Files.Count; i++)
                {
                    var postedFile = httpRequest.Files[i];
                    var fileName = Path.GetFileNameWithoutExtension(postedFile.FileName);
                    var fileext = Path.GetExtension(postedFile.FileName);
                    var fileName1 = "_E2bdADS__" + fileName + randomno() + fileext;
                    var filePath = folderPath + Path.GetFileName(fileName1); //HttpContext.Current.Server.MapPath(+ postedFile.FileName);
                    var fileextchk = Path.GetExtension(postedFile.FileName);
                    var is_valid = SaveCommonModulesDocument.chkValidExtension(fileextchk);
                    postedFile.SaveAs(filePath);
                    docfiles.Add(filePath);
                    string input = filePath;
                    string tempflname = fileName1;
                    tempflname = tempflname.Remove(0, 10);
                    myList.Add(tempflname);
                    string output = folderPath + Path.GetFileName(tempflname);
                    QueryAES.FileEncrypt(input, output);
                    //delete file
                    try
                    {
                        var status = AzureDocumentself.filecreateafteredit(output, folderpathazure, Path.GetFileName(tempflname), null, null);
                    }
                    catch (Exception er)
                    {
                        AzureDocumentself.CreateNestedDirectory(folderpathazure);
                        var status = AzureDocumentself.filecreateafteredit(output, folderpathazure, Path.GetFileName(tempflname), null, null);
                    }
                    System.IO.File.Delete(input);
                }
            }
            //upload file
            var filearray = myList.ToArray();
            postedFiledata = string.Join("/", filearray);
            string id = "";
            ObjectParameter IDParameter;
            IDParameter = new ObjectParameter("id", id);
            //insert in Notice   
            var insertdata = db.Usp_SaveNotice(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), nsubject, details, nparty, aparty, noparty, aoparty, ndate, place, token, IDParameter, null);
            id = Convert.ToString(IDParameter.Value);

            //save users
            if (userlist == "null")
            {
                userlist = "";
            }
            if (userlist != "")
            {
                var um = new ActivityUserMap();
                var eachId1 = userlist.Split(new[] { "," }, StringSplitOptions.RemoveEmptyEntries).Distinct();
                foreach (var item1 in eachId1)
                {
                    var ct1 = db.Usp_SaveNoticeUser(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), id, item1.ToString());
                }
                //delete not in rows
                var entryuser = db.GetDeleteNoticeUser(LoggedInUser.FirmId.ToString(), id.ToString(), userlist.ToString()).ToList();
                if (entryuser.Count > 0)
                {
                    foreach (var itemp in entryuser)
                    {
                        var dt = db.insertdeleteentrytable(Guid.Parse(itemp.Id.ToString()), "Tbl_NoticeUser", LoggedInUser.FirmId);
                    }
                    var counts = db.deleteNoticeUser(LoggedInUser.FirmId.ToString(), id.ToString(), userlist);
                    db.SaveChanges();
                }
            }
            //insert notice file

            if (postedFiledata != "")
            {
                string[] values = postedFiledata.Split('/');
                for (int i = 0; i < values.Length; i++)
                {
                    values[i] = values[i].Trim();
                    var insertfile = db.Usp_SaveNoticeFile(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), id, values[i]);
                }
            }
            return Ok();
        }

