                        var insertfile = db.Usp_SaveReplyNoticeFile(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), nid, id, values[i]);
                    }
                }
                //send email to user
                try
                {
                    if (auser != null)
                    {
                        string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                        //send email to user
                        string msgbody = details;
                        //string msgsubject = "Regarding Case Notice from mykase";
                        string strsubject = "", strbody = "";
                        strsubject = "Regarding Notice from Mykase.";
                        strbody += "Dear User,<br><br>";
                        strbody += "Message: " + details + "<br><br>";
                        strbody += "Notice Details: " + newdetails + "<br><br>";
                        strbody += "Date :" + @String.Format("{0:dd MMM yyyy hh:mm:ss}", DateTime.Now.ToString()) + "<br><br>";
                        strbody += "Thanks & Regards,<br>Mykase<br><br>";
                        try
                        {
                            string attchment = postedFiledatamail;
                            if (attchment != null)
                            {

                                attchment = attchment.Replace("|", ",");
                            }
                            CommomUtility objmail = new CommomUtility();
                            objmail.SendEmail(fromemail, auser, "", strsubject, strbody, attchment);
                        }
                        catch (Exception ex)
                        {

                        }
                        //remove files
                        try
                        {
                            var attchment = postedFiledatamail;
                            if (attchment.ToString().Trim() != "")
                            {
                                string[] CCattach = attchment.Split(',');
                                foreach (string ccattached in CCattach)
                                {
                                    if (!string.IsNullOrEmpty(ccattached))
                                    {
                                        if (File.Exists(ccattached))
                                        {
                                            System.IO.File.Delete(ccattached);
                                        }
                                        else
                                        {
                                            attchment = "";
                                        }
                                    }
                                }
                            }

                        }
                        catch (Exception er)
                        {
                        }
                    }
                }
                catch (Exception er)
                {

                }
                var param = controllername + ">ReplyNotice>param=" + ml.mfile + "@" + postedFiledata + "@" + Firmid + "@" + userid + "@" + details + "@" + auser;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Message), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Message), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), LoggedInUser.UserId, param, myIP(), GetMacAddress().ToString(), 0, "");
                return Ok();
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Message), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Message), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

