        /// <summary>
        /// Save Case Task
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SaveCaseTask()
        {
            try
            {
                var db = new LawPracticeEntities();
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                var caseid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["caseid"]);
                var assignuser = QueryAES.UrlDecode(HttpContext.Current.Request.Form["assignuser"]);
                var tasktype = QueryAES.UrlDecode(HttpContext.Current.Request.Form["tasktype"]);
                var duedate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["duedate"]);
                var actionbydate = QueryAES.UrlDecode(HttpContext.Current.Request.Form["actionbydate"]);
                var details = QueryAES.UrlDecode(HttpContext.Current.Request.Form["details"]);
                var clientid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["client"]);
                var tasksubject = QueryAES.UrlDecode(HttpContext.Current.Request.Form["tasksubject"]);
                var savemykasefileid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["savemykasefileid"]);
                if (savemykasefileid.ToString() == "undefined")
                {
                    savemykasefileid = "";
                }
                if (String.IsNullOrEmpty(caseid))
                {
                    caseid = Guid.Empty.ToString();
                }
                if (!String.IsNullOrEmpty(clientid))
                {
                    clientid = clientid.TrimEnd(',').TrimStart(',');
                }

                if (String.IsNullOrEmpty(clientid))
                {
                    clientid = Guid.Empty.ToString();
                }
                var myList = new List<string>();
                var docfiles = new List<string>();
                var docsize = new List<string>();

                // Add items to the list
                dynamic postedFiledata = "";
                dynamic postedFiledata1 = "";

                var ml = new MessageList();
                var InfectedFilesResult = "";
                // Add items to the list
                var httpRequest = HttpContext.Current.Request;
                //check size of storage
                if (httpRequest.Files.Count > 0 || (!String.IsNullOrEmpty(savemykasefileid)))
                {
                    var doclimit = DocumentQuota.CheckDocumentmanagementFileSize(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                    if (doclimit.ToString() != "Available")
                    {
                        return Ok(new { Result = doclimit, InfectFiles = InfectedFilesResult });
                    }
                }

                //end size of storage
                if (httpRequest.Files.Count > 0)
                {

                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var postedFile = httpRequest.Files[i];
                        DocUploadResult DUResult = new DocUploadResult();
                        DUResult = SaveCommonModulesDocument.UploadDocument(postedFile, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), "task", true);
                        myList.Add(DUResult.FileName);
                        docsize.Add(DUResult.FileSize);
                        docfiles.Add(DUResult.EmailFilePath);
                        if (!String.IsNullOrEmpty(DUResult.InfectedFile))
                        {
                            InfectedFilesResult += DUResult.InfectedFile.ToString() + ",";
                        }
                    }
                }
                InfectedFilesResult = InfectedFilesResult.TrimEnd(',');
                var filearrayd = docfiles.ToArray();
                var sendemailpostedFiledata = string.Join(",", filearrayd);
                var filearray = myList.ToArray();
                postedFiledata = string.Join("|", filearray);
                string[] values = assignuser.TrimStart(',').TrimEnd(',').Split(',');
                for (int i = 0; i < values.Length; i++)
                {
                    values[i] = values[i].Trim();
                    if (!String.IsNullOrEmpty(values[i]))
                    {
                        string id = "";
                        ObjectParameter IDParameter;
                        IDParameter = new ObjectParameter("id", id);
                        var data = db.Usp_SaveFirmCaseTaskNew(firmid, userid, values[i], caseid, tasktype, duedate, actionbydate, details, IDParameter, clientid, tasksubject);
                        id = Convert.ToString(IDParameter.Value);
                        var dataac = Notification.SaveNotifications("AssignTask", null, firmid, userid, values[i], LoggedInUser.UserName);
                        //save file
                        var s = postedFiledata;
                        if (s != "")
                        {
                            string[] values1 = s.Split('|');
                            for (int j = 0; j < values1.Length; j++)
                            {
                                values1[j] = values1[j].Trim();

                                var chkout = db.Usp_SaveMultipleFileMap(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), id.ToString(), values1[j], "task", docsize[j]);
                            }
                        }
                        if (!String.IsNullOrEmpty(savemykasefileid))
                        {
                            //upload docuemnt from mykase server
                            try
                            {
                                var filelist = SaveMykaseDocument.SaveMykaseDocumentToOtherModule(savemykasefileid, "task", LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                                if (!String.IsNullOrEmpty(filelist))
                                {
                                    string[] values2 = filelist.Split('|');
                                    for (int j = 0; j < values2.Length; j++)
                                    {
                                        values2[j] = values2[j].Trim();
                                        var Docsizes = "0";
                                        try
                                        {
                                            string[] valuessize = savemykasefileid.Split(',');
                                            {
                                                var documentdetails = db.usp_CheckFilefolderCloud(LoggedInUser.FirmId.ToString(), valuessize[j]).FirstOrDefault();
                                                if (documentdetails != null)
                                                {
                                                    Docsizes = Convert.ToString(documentdetails.DocSize);
                                                }
                                            }
                                        }
                                        catch (Exception ex)
                                        {

                                        }
                                        var chkout = db.Usp_SaveMultipleFileMap(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), id.ToString(), values2[j], "task", Docsizes);
                                    }

                                }
                            }
                            catch
                            {

                            }
                        }
                        //send email to asignee
                        var stringcontent = "";
                        var stringsubject = "";
                        try
                        {
                            var checkcaseornot = db.usp_gettaskdetailsbyid(firmid, userid, id).FirstOrDefault();
                            if (checkcaseornot != null)
                            {
                                //get AssignorName
                                var AssigneesName = db.usp_GetFirmUsers_RegUser_by_Id(values[i], LoggedInUser.FirmId.ToString()).FirstOrDefault();
                                //get AssigneesName
                                var AssignorName = db.usp_GetFirmUsers_RegUser_by_Id(LoggedInUser.UserId.ToString(), LoggedInUser.FirmId.ToString()).FirstOrDefault();
                                //get mykaselink
                                string mykaselink = WebConfigurationManager.AppSettings["SiteUrl"].ToString();
                                CommomUtility objmail = new CommomUtility();
                                string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                                string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["basicmailtemplate"].ToString();
                                var result = db.usp_GetEmailTemplate("TaskAssign").FirstOrDefault();
                                stringcontent = result.EmailContent;
                                stringsubject = result.EmailSubject;
                                stringcontent = stringcontent.Replace("#AssignorName#", AssignorName.cfname);
                                stringcontent = stringcontent.Replace("#AssigneesName#", AssigneesName.cfname);
                                if (!String.IsNullOrEmpty(checkcaseornot.MatterName.ToString()))
                                {
                                    stringcontent = stringcontent.Replace("#MatterName#", "<strong>Matter: </strong>" + checkcaseornot.MatterName + "<br/><br/>");
                                }
                                else
                                {
                                    stringcontent = stringcontent.Replace("#MatterName#", "");
                                }
                                stringcontent = stringcontent.Replace("#TaskName#", checkcaseornot.TaskName);
                                if (!String.IsNullOrEmpty(checkcaseornot.TaskSubject.ToString()))
                                {
                                    stringcontent = stringcontent.Replace("#Subject#", "<strong>Subject: </strong>" + checkcaseornot.TaskSubject + "<br/><br/>");
                                }
                                else
                                {
                                    stringcontent = stringcontent.Replace("#Subject#", "");
                                }
                                stringcontent = stringcontent.Replace("#DueDate#", String.Format("{0:dd MMM yyyy}", checkcaseornot.TaskDueDate));
                                stringcontent = stringcontent.Replace("#mykaselink#", mykaselink);
                                if (!String.IsNullOrEmpty(checkcaseornot.TDetails))
                                {
                                    stringcontent = stringcontent.Replace("#Note#", "<strong>Note: </strong>" + checkcaseornot.TDetails + "<br/><br/>");
                                }
                                else
                                {
                                    stringcontent = stringcontent.Replace("#Note#", "");
                                }
                                stringcontent = stringcontent.Replace("#AcceptReject#", String.Format("{0:dd MMM yyyy}", checkcaseornot.ActionByDate));


                                AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#CONTENT#", stringcontent);
                                objmail.SendEmail(fromemail, AssigneesName.EmailId, "", stringsubject, AssignmentSubmittedMailBody, "");
                            }
                        }
                        catch
                        {

                        }
                    }
                }
                try
                {
                    var data = db.usp_GetDefaultTask(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).Where(x => x.Id.ToString() == tasktype).FirstOrDefault();
                    string notification = "You have Created a task(" + data.CaseTaskName + ")";
                    db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "CreateTask", null, null);
                }
                catch
                {
                }
                return Ok(new { Result = 1, InfectFiles = InfectedFilesResult });
            }
            catch (Exception ed)
            {
                return Ok(ed.Message);
            }
        }

