        /// <summary>
        /// Send Reminder
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SendReminder()
        {
            try
            {
                var db = new LawPracticeEntities();
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                var token = QueryAES.UrlDecode(HttpContext.Current.Request.Form["tokenid"]);
                try
                {
                    token = token.Replace(" ", "+");
                    token = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(token));
                }
                catch (Exception ex)
                {

                }
                var txtRemarkMsg = HttpContext.Current.Request.Form["txtAccRejMsg"];
                var result = db.usp_GetCaseTaskBeforeActionByTaskId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), token).FirstOrDefault();
                if (result != null)
                {
                    string AlertId = Convert.ToString(result.AlertId);
                    string Firmid = Convert.ToString(result.Firmid);
                    string CreateUserId = Convert.ToString(result.CreateUserId);
                    string AssignUserId = Convert.ToString(result.AssignUserId);
                    string TaskDueDate = Convert.ToString(result.TaskDueDate);
                    string ActionByDate = Convert.ToString(result.ActionByDate);
                    string CaseTaskName = Convert.ToString(result.CaseTaskName);
                    string CreaterEmail = Convert.ToString(result.CreaterEmail);
                    string CreaterMobile = Convert.ToString(result.CreaterMobile);
                    string CreaterFName = Convert.ToString(result.CreaterFName);
                    string AssignUserEmail = Convert.ToString(result.AssignUserEmail);
                    string AssignUserMobile = Convert.ToString(result.AssignUserMobile);
                    string AssignUserFName = Convert.ToString(result.AssignUserFName);
                    string TDetails = Convert.ToString(result.TDetails);
                    string TaskSubject = Convert.ToString(result.TaskSubject);
                    string CaseId = Convert.ToString(result.CaseId);
                    string MatterName = Convert.ToString(result.MatterName);
                    try
                    {
                        CreaterMobile = CreaterMobile.Replace(" ", "+");
                        CreaterMobile = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(CreaterMobile));
                        CreaterFName = CreaterFName.Replace(" ", "+");
                        CreaterFName = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(CreaterFName));
                        AssignUserMobile = AssignUserMobile.Replace(" ", "+");
                        AssignUserMobile = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(AssignUserMobile));
                        AssignUserFName = AssignUserFName.Replace(" ", "+");
                        AssignUserFName = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(AssignUserFName));
                    }
                    catch (Exception e)
                    {

                    }
                    string SMSText = "";
                    string RemarkDetail = "<strong>Remarks: </strong>" + txtRemarkMsg;
                    string TaskSubjecttxt = "<strong>Subject :</strong> " + TaskSubject;
                    string TDetailstxt = "<strong>Note :</strong> " + TDetails;
                    string matternametxt = "<strong>Matter :</strong> " + MatterName;
                    string actionDate = "<strong>Accept/Reject by :</strong> " + Convert.ToDateTime(ActionByDate).ToString("dd/MM/yyyy");
                    string msubject = "myKase Reminder- Accept/Reject the task";
                    string Footerline = "<p>Please login to your <a href = 'https://www.mykase.in/' target = '_blank'> myKase </a> account and take necessary action before the due date.</p>";
                    //Mail to Assignee
                    if (!string.IsNullOrEmpty(AssignUserEmail))
                    {
                        string textmessage = "Please Accept/Reject the following task assigned by " + CreaterFName + ". Details are as follows:";
                        //string textmessage = "The Last Date to Accept/Reject  the task "+ CaseTaskName + " is "+Convert.ToDateTime(ActionByDate).ToString("dd/MM/yyyy") +".Please take appropriate action.";
                        string emailresponse = SendCaseTaskAlertMail(AssignUserEmail, AssignUserFName, textmessage, CaseTaskName, actionDate, msubject, TDetails, TaskSubject, MatterName, Footerline, RemarkDetail);
                        if (emailresponse.ToLower() == "sent")
                        {
                            string message = ConfigurationManager.AppSettings["TaskAssigneeAlertBody"].ToString();
                            message = message.Replace("#User#", AssignUserFName.Replace("+", " "));
                            message = message.Replace("#TaskName#", CaseTaskName);
                            message = message.Replace("#TextRemark#", RemarkDetail);

                            if (!String.IsNullOrEmpty(MatterName))
                            {
                                message = message.Replace("#MatterName#", matternametxt);
                            }
                            else
                            {
                                message = message.Replace("#MatterName#", "");
                            }

                            message = message.Replace("#DueDate#", actionDate);
                            message = message.Replace("#TextMessage#", textmessage);

                            if (!String.IsNullOrEmpty(TaskSubject))
                            {
                                message = message.Replace("#SubjectName#", TaskSubjecttxt);
                            }
                            else
                            {
                                message = message.Replace("#SubjectName#", "");
                            }

                            if (!String.IsNullOrEmpty(TDetails))
                            {
                                message = message.Replace("#TaskNote#", TDetailstxt);
                            }
                            else
                            {
                                message = message.Replace("#TaskNote#", "");
                            }
                            message = message.Replace("#FooterLine#", Footerline);
                            var savecount = db.SaveServicelogdata(Firmid, AssignUserId, "Email", message, AssignUserEmail, AssignUserMobile, AlertId, ActionByDate, "0");
                            var savenoti = db.saveuseractivity(Firmid, LoggedInUser.UserId.ToString(), AssignUserId, 0, "Please Accept/Reject the  task:" + CaseTaskName + " assigned by " + CreaterFName + "", "TaskRemind", AlertId, "", "", DateTime.Now.ToString());
                            return Ok();
                        }
                        else
                        {
                            return Ok("NoTaskFound");
                        }
                    }
                }
                return Ok();
            }
            catch (Exception ed)
            {
                return Ok(ed.Message);
            }
        }

        /// <summary>
        /// Send Case Task Alert Mail
        /// </summary>
        /// <param name="email"></param>
        /// <param name="name"></param>
        /// <param name="textmessage"></param>
        /// <param name="Task"></param>
        /// <param name="date"></param>
        /// <param name="msubject"></param>
        /// <param name="TDetails"></param>
        /// <param name="TaskSubject"></param>
        /// <param name="MatterName"></param>
        /// <param name="Footerline"></param>
        /// <returns></returns>
        public string SendCaseTaskAlertMail(string email, string name, string textmessage, string Task, string date, string msubject, string TDetails, string TaskSubject, string MatterName, string Footerline,string RemarkDetail="")
        {
            string message = "";
            string subjectline = ConfigurationManager.AppSettings["TaskAssigneeAlertSubject"].ToString();
            message = ConfigurationManager.AppSettings["TaskAssigneeAlertBody"].ToString();
            string mailsubject = ConfigurationManager.AppSettings["TaskAssigneeAlertSubject"].ToString();
            mailsubject = mailsubject.Replace("#mailSubject#", msubject);
            message = message.Replace("#User#", name.Replace("+", " "));
            message = message.Replace("#TaskName#", Task);
            message = message.Replace("#DueDate#", date);
            message = message.Replace("#TextMessage#", textmessage);
            message = message.Replace("#TextRemark#", RemarkDetail);

            string TaskSubjecttxt = "<strong>Subject :</strong> " + TaskSubject;
            if (!String.IsNullOrEmpty(TaskSubject))
            {
                message = message.Replace("#SubjectName#", TaskSubjecttxt);
            }
            else
            {
                message = message.Replace("#SubjectName#", "");
            }
            string TDetailstxt = "<strong>Note :</strong> " + TDetails;
            if (!String.IsNullOrEmpty(TDetails))
            {
                message = message.Replace("#TaskNote#", TDetailstxt);
            }
            else
            {
                message = message.Replace("#TaskNote#", "");
            }
            message = message.Replace("#FooterLine#", Footerline);
            string matternametxt = "<strong>Matter :</strong> " + MatterName;

            if (!String.IsNullOrEmpty(MatterName))
            {
                message = message.Replace("#MatterName#", matternametxt);
            }
            else
            {
                message = message.Replace("#MatterName#", "");
            }
            string mail = "failed";
            string server = null;
            string port = null;
            server = ConfigurationManager.AppSettings["EmailSMTP"].ToString();
            port = ConfigurationManager.AppSettings["EmailPort"].ToString();
            string To = email;
            string EmailId = ConfigurationManager.AppSettings["fromemail"].ToString();
            try
            {
                if (email.ToString().Trim() != "")
                {
                    string mailFrom = EmailId;
                    string mailFromName = EmailId;
                    string mailHost = server;
                    bool isSSLMail = false;
                    bool useDefaultMailCredentials = Convert.ToBoolean(false);
                    int smtpPort = Convert.ToInt32(port);
                    string regMailFromUserName = EmailId;
                    string regMailFromPassword = "";
                    //string adminEmail = "";
                    System.Net.Mail.MailMessage mm = new System.Net.Mail.MailMessage();
                    System.Net.Mail.MailAddress mailFromAddress = new System.Net.Mail.MailAddress(mailFrom, mailFromName);
                    mm.To.Add(new System.Net.Mail.MailAddress(email));
                    mm.From = new System.Net.Mail.MailAddress(mailFromName);
                    mm.Subject = mailsubject;// Subject;
                    string strbody = message;
                    mm.Body = strbody;
                    mm.IsBodyHtml = true;
                    System.Net.Mail.SmtpClient smtp = new System.Net.Mail.SmtpClient();
                    smtp.Host = mailHost;
                    smtp.EnableSsl = isSSLMail;
                    System.Net.NetworkCredential NetworkCred = new System.Net.NetworkCredential(regMailFromUserName, regMailFromPassword);
                    smtp.UseDefaultCredentials = useDefaultMailCredentials;
                    smtp.Credentials = NetworkCred;
                    smtp.Port = smtpPort;
                    smtp.Send(mm);
                    mail = "sent";
                }
            }
            catch
            {
            }

            return mail;
        }

        /// <summary>
        /// Send Reminder over due
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SendReminderoverdue()
        {
            try
            {
                var db = new LawPracticeEntities();
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                var token = QueryAES.UrlDecode(HttpContext.Current.Request.Form["tokenid"]);
                var remarks = QueryAES.UrlDecode(HttpContext.Current.Request.Form["remarks"]);
                try
                {
                    token = token.Replace(" ", "+");
                    token = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(token));
                }
                catch (Exception ex)
                {

                }
                var result = db.usp_GetCaseTaskBeforeActionByTaskId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), token).FirstOrDefault();
                if (result != null)
                {
                    string AlertId = Convert.ToString(result.AlertId);
                    string Firmid = Convert.ToString(result.Firmid);
                    string CreateUserId = Convert.ToString(result.CreateUserId);
                    string AssignUserId = Convert.ToString(result.AssignUserId);
                    string TaskDueDate = Convert.ToString(result.TaskDueDate);
                    string ActionByDate = Convert.ToString(result.ActionByDate);
                    string CaseTaskName = Convert.ToString(result.CaseTaskName);
                    string CreaterEmail = Convert.ToString(result.CreaterEmail);
                    string CreaterMobile = Convert.ToString(result.CreaterMobile);
                    string CreaterFName = Convert.ToString(result.CreaterFName);
                    string AssignUserEmail = Convert.ToString(result.AssignUserEmail);
                    string AssignUserMobile = Convert.ToString(result.AssignUserMobile);
                    string AssignUserFName = Convert.ToString(result.AssignUserFName);
                    string TDetails = Convert.ToString(result.TDetails);
                    string TaskSubject = Convert.ToString(result.TaskSubject);
                    string CaseId = Convert.ToString(result.CaseId);
                    string MatterName = Convert.ToString(result.MatterName);
                    try
                    {
                        CreaterMobile = CreaterMobile.Replace(" ", "+");
                        CreaterMobile = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(CreaterMobile));
                        CreaterFName = CreaterFName.Replace(" ", "+");
                        CreaterFName = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(CreaterFName));
                        AssignUserMobile = AssignUserMobile.Replace(" ", "+");
                        AssignUserMobile = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(AssignUserMobile));
                        AssignUserFName = AssignUserFName.Replace(" ", "+");
                        AssignUserFName = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(AssignUserFName));
                    }
                    catch (Exception e)
                    {

                    }
                    string SMSText = "";

                    string TaskSubjecttxt = "<strong>Subject :</strong> " + TaskSubject;
                    string TDetailstxt = "<strong>Note :</strong> " + TDetails;
                    string duedate = "<strong>Due Date :</strong> " + Convert.ToDateTime(TaskDueDate).ToString("dd/MM/yyyy");
                    string matternametxt = "<strong>Matter :</strong> " + MatterName;
                    string msubject = "myKase Reminder- Overdue Task";
                    string Footerline = "<p>Please login to your <a href = 'https://www.mykase.in/' target = '_blank'> myKase </a> account and take necessary action before the due date.</p>";
                    //Mail to Assignee
                    if (!string.IsNullOrEmpty(AssignUserEmail))
                    {
                        string textmessage = "The following task assigned by " + CreaterFName + " is overdue. Details are as follows:";
                        if (!String.IsNullOrEmpty(remarks))
                        {
                            textmessage += "<br/><br/><strong>Remarks:</strong> " + remarks;
                        }
                        string emailresponse = SendCaseTaskAlertMail(AssignUserEmail, AssignUserFName, textmessage, CaseTaskName, duedate, msubject, TDetails, TaskSubject, MatterName, Footerline,"");
                        if (emailresponse.ToLower() == "sent")
                        {
                            string message = ConfigurationManager.AppSettings["TaskAssigneeAlertBody"].ToString();
                            message = message.Replace("#User#", AssignUserFName.Replace("+", " "));
                            message = message.Replace("#TaskName#", CaseTaskName);

                            if (!String.IsNullOrEmpty(MatterName))
                            {
                                message = message.Replace("#MatterName#", matternametxt);
                            }
                            else
                            {
                                message = message.Replace("#MatterName#", "");
                            }

                            message = message.Replace("#DueDate#", duedate);
                            message = message.Replace("#TextMessage#", textmessage);

                            if (!String.IsNullOrEmpty(TaskSubject))
                            {
                                message = message.Replace("#SubjectName#", TaskSubjecttxt);
                            }
                            else
                            {
                                message = message.Replace("#SubjectName#", "");
                            }

                            if (!String.IsNullOrEmpty(TDetails))
                            {
                                message = message.Replace("#TaskNote#", TDetailstxt);
                            }
                            else
                            {
                                message = message.Replace("#TaskNote#", "");
                            }


                            message = message.Replace("#FooterLine#", Footerline);

                            var savecontent = db.usp_SaveTaskEmailContent(Firmid, LoggedInUser.UserId.ToString(), AlertId, remarks, "OverDueSend");

                            var savecount = db.SaveServicelogdata(Firmid, AssignUserId, "Email", message, AssignUserEmail, AssignUserMobile, AlertId, ActionByDate, "0");
                            var savenoti = db.saveuseractivity(Firmid, LoggedInUser.UserId.ToString(), AssignUserId, 0, "the  task:" + CaseTaskName + " assigned by " + CreaterFName + " is overdue", "TaskRemind", AlertId, "", "", DateTime.Now.ToString());
                            return Ok();
                        }
                        else
                        {
                            return Ok("NoTaskFound");
                        }
                    }
                }
                return Ok();
            }
            catch (Exception ed)
            {
                return Ok(ed.Message);
            }
        }

