        /// <summary>
        /// Schedule Task Assign user
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult ScheduleTaskAssignuser()
        {
            try
            {
                var db = new LawPracticeEntities();
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                List<usp_getScheduleTaskAssignUser_Result> list = new List<usp_getScheduleTaskAssignUser_Result>();
                list = db.usp_getScheduleTaskAssignUser(firmid, userid).ToList();
                foreach (var datas in list.ToList())
                {
                    usp_getScheduleTaskAssignUser_Result newItem = new usp_getScheduleTaskAssignUser_Result();
                    if (!string.IsNullOrEmpty(datas.UserName))
                    {
                        newItem.UserName = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(datas.UserName.ToString()));
                        list[list.IndexOf(datas)].UserName = newItem.UserName;
                    }
                }
                return Ok(list);
            }
            catch (Exception ex)
            {
                db1.usp_AddAudit(Convert.ToInt32(EventType.User), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.User), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

        /// <summary>
        /// Save Case Comm unique
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult SaveCaseCommunique()
        {
            try
            {
                var db = new LawPracticeEntities();
                var myList = new List<string>();
                var docfiles = new List<string>();
                var docsize = new List<string>();
                // Add items to the list
                dynamic postedFiledata = "";
                dynamic postedFiledata1 = "";
                var ml = new MessageList();
                var InfectedFilesResult = "";
                // Add items to the list
                var savemykasefileid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["savemykasefileid"]);
                if (savemykasefileid.ToString() == "undefined")
                {
                    savemykasefileid = "";
                }
                var httpRequest = HttpContext.Current.Request;
                //check size of storage
                if (httpRequest.Files.Count > 0 || (!String.IsNullOrEmpty(savemykasefileid)))
                {
                    var doclimit = DocumentQuota.CheckDocumentmanagementFileSize(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                    if (doclimit.ToString() != "Available")
                    {
                        return Ok(new { Result = doclimit, InfectFiles = InfectedFilesResult });
                    }
                }
                if (httpRequest.Files.Count > 0)
                {
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var postedFile = httpRequest.Files[i];
                        DocUploadResult DUResult = new DocUploadResult();
                        DUResult = SaveCommonModulesDocument.UploadDocument(postedFile, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), "communique", true);
                        myList.Add(DUResult.FileName);
                        docsize.Add(DUResult.FileSize);
                        docfiles.Add(DUResult.EmailFilePath);
                        if (!String.IsNullOrEmpty(DUResult.InfectedFile))
                        {
                            InfectedFilesResult += DUResult.InfectedFile.ToString() + ",";
                        }
                    }
                }
                InfectedFilesResult = InfectedFilesResult.TrimEnd(',');
                var filearrayd = docfiles.ToArray();
                var sendemailpostedFiledata = string.Join(",", filearrayd);
                var filearray = myList.ToArray();
                postedFiledata = string.Join("|", filearray);
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                var caseid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["caseid"]);
                var member = QueryAES.UrlDecode(HttpContext.Current.Request.Form["member"]);
                var inftype = QueryAES.UrlDecode(HttpContext.Current.Request.Form["inftype"]);
                var details = QueryAES.UrlDecode(HttpContext.Current.Request.Form["details"]);
                var subject = QueryAES.UrlDecode(HttpContext.Current.Request.Form["subject"]);
                string id = "";
                ObjectParameter IDParameter;
                IDParameter = new ObjectParameter("id", id);
                //save data
                var insertdata = db.Usp_SaveCasecommunique(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), caseid.ToString(), inftype, details, subject, IDParameter);
                id = Convert.ToString(IDParameter.Value);
                //save file
                var s = postedFiledata;
                if (s != "")
                {
                    string[] values1 = s.Split('|');
                    for (int j = 0; j < values1.Length; j++)
                    {
                        values1[j] = values1[j].Trim();
                        var chkout = db.Usp_SaveMultipleFileMap(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), id.ToString(), values1[j], "communique", docsize[j]);
                    }
                }
                if (!String.IsNullOrEmpty(savemykasefileid))
                {
                    //upload docuemnt from mykase server
                    try
                    {
                        var filelist = SaveMykaseDocument.SaveMykaseDocumentToOtherModule(savemykasefileid, "communique", LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString());
                        if (!String.IsNullOrEmpty(filelist))
                        {
                            string[] values2 = filelist.Split('|');
                            for (int j = 0; j < values2.Length; j++)
                            {
                                values2[j] = values2[j].Trim();
                                var Docsizes = "0";
