        /// <summary>
        /// Load Common Dropdown
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult LoadCommonDropdown()
        {
            try
            {
                string dropdownname = QueryAES.UrlDecode(HttpContext.Current.Request.Form["dropdownname"]);
                var cacheKey = "LoadCommonDropdown_" + dropdownname + "_" + LoggedInUser.FirmId.ToString();
                var cached = HttpContext.Current.Cache[cacheKey];
                if (cached != null)
                    return Ok(cached);

                var cmatter = db1.usp_GetCommonDropdownData(dropdownname, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).ToList();
                HttpContext.Current.Cache.Insert(cacheKey, cmatter, null, DateTime.Now.AddMinutes(5), TimeSpan.Zero);
                return Ok(cmatter);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

        /// <summary>
        /// Batch version — accepts multiple dropdown names and returns all results in one call
        /// </summary>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult LoadCommonDropdownBatch()
        {
            try
            {
                var namesJson = HttpContext.Current.Request.Form["dropdownnames"];
                var dropdownNames = JsonConvert.DeserializeObject<List<string>>(namesJson);
                var firmId = LoggedInUser.FirmId.ToString();
                var userId = LoggedInUser.UserId.ToString();
                var results = new Dictionary<string, List<usp_GetCommonDropdownData_Result>>();

                foreach (var name in dropdownNames)
                {
                    var cacheKey = "LoadCommonDropdown_" + name + "_" + firmId;
                    var cached = HttpContext.Current.Cache[cacheKey] as List<usp_GetCommonDropdownData_Result>;
                    if (cached != null)
                    {
                        results[name] = cached;
                        continue;
                    }
                    var data = db1.usp_GetCommonDropdownData(name, firmId, userId).ToList();
                    HttpContext.Current.Cache.Insert(cacheKey, data, null, DateTime.Now.AddMinutes(5), TimeSpan.Zero);
                    results[name] = data;
                }
                return Ok(results);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

        /// <summary>
        /// Create Client Login
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]

        public IHttpActionResult CreateClientLogin()
        {
            try
            {
                var clientlimit = "";
                string memberuserids = string.Empty;
                string Loginuserids = string.Empty;
                var matteridname = WebConfigurationManager.AppSettings["matteridname"];
                var apiUrl = ConfigurationManager.AppSettings["savetocasewatchurl"];
                //add login data
                var addfClient = new WebClient();

                var db = new LawPracticeEntities();
                var getusercount = db.usp_GetFirmLimit(LoggedInUser.FirmId.ToString()).FirstOrDefault();
                if (getusercount != null)
                {
                    clientlimit = getusercount.iClientPortalLimit;
                    if (String.IsNullOrEmpty(clientlimit))
                    {
                        return Ok("invalid user license");
                    }
                    var ausercount = db.Usp_GetFirmActiveClient(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
                    if (ausercount < Convert.ToInt32(clientlimit))
                    {
                        var userid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["userid"]);
                        var cpassword = QueryAES.UrlDecode(HttpContext.Current.Request.Form["cpassword"]);
                        var encpassword = "";
                        var token = QueryAES.UrlDecode(HttpContext.Current.Request.Form["token"]);
                        try
                        {
                            token = token.Replace(" ", "+");
                            token = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(token));
                        }
                        catch (Exception ex)
                        {

                        }
                        if (!String.IsNullOrEmpty(cpassword) || cpassword != "undefined")
                        {
                            encpassword = QueryAES.GetHashedCode(cpassword);
                            encpassword = encpassword.Replace("\n", "");
                        }
                        else
                        {
                            return Ok("Invalid password");
                        }
                        if (!String.IsNullOrEmpty(userid) || userid != "undefined")
                        {
                        }
                        else
                        {
                            return Ok("Invalid userId.");
                        }
                        var checkuser = db.CommonValidationByUserName(userid).FirstOrDefault();
                        if (checkuser == 1)
                        {
                            return Ok("ExistUserID");
                        }
                        var loggedInUserIdDetail = LoggedInUser.UserId.ToString();
                        var getuseremailmobile = DataAccessADO.GetCompleteUserDetailByUserID(LoggedInUser.FirmId.ToString(), token);

                        using (var transaction = db.Database.BeginTransaction())
                        {
                            try
                            {
                                var count = db.usp_CreateClientCredentials(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), token, userid, encpassword);
                                try
                                {
                                    var dataac = Notification.SaveNotifications("CreateClientCred", null, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), token.ToString(), LoggedInUser.UserName);
                                    //get alluser relate to client
                                    var data = db.usp_getAllUserrelatedtoClient(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), token).ToList();
                                    if (data != null)
                                    {
                                        foreach (var item in data)
                                        {
                                            var dataac2 = Notification.SaveNotifications("CreateClientCredUser", null, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), item.Value.ToString(), LoggedInUser.UserName);
                                        }
                                    }
                                }
                                catch
                                {

                                }
                                if (count > 0)
                                {
                                    //send email to client mail
                                    //get client data;
                                    var Email = db.usp_GetEmailByUserId(LoggedInUser.FirmId.ToString(), token).FirstOrDefault();
                                    if (Email != null)
                                    {
                                        string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                                        string AssignmentSubmittedMailSubject = WebConfigurationManager.AppSettings["ClientRegistrationSubject"].ToString();
                                        string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["ClientRegistrationBody"].ToString();
                                        AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#USERNAME", userid);
                                        AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#PASSWORD", cpassword);
                                        AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#SubscriberName", LoggedInUser.UserFullName);
                                        string AssignmentSubmittedMailBody1 = WebConfigurationManager.AppSettings["basicmailtemplate"].ToString();
                                        AssignmentSubmittedMailBody1 = AssignmentSubmittedMailBody1.Replace("#CONTENT#", AssignmentSubmittedMailBody);
                                        try
                                        {

                                            if (getuseremailmobile != null && getuseremailmobile.Rows.Count > 0)
                                            {
                                                DataRow row = getuseremailmobile.Rows[0];

                                                var email = row["EmailId"].ToString();
                                                var mobile = row["cmobile"].ToString();
                                                var dispName = row["Name"].ToString();
                                                var country = row["country"].ToString();
                                                var state = row["cstate"].ToString();
                                                var userId = "Mykase_" + loggedInUserIdDetail;
                                                var SubsStartDate = row["StatDate"].ToString();
                                                var SubscriptionEndDate = row["EndDate"].ToString();
                                                var RoleId = Convert.ToInt32(row["RoleId"]);

                                                var AdminUserId = "";
                                                if (row["IsAdminCW"].ToString() == "1")
                                                {

                                                    memberuserids = "";//getuserdata.UserName;//row["UserName"].ToString();
                                                    AdminUserId = row["FirmAdminUserName"].ToString();
                                                }
                                                else
                                                {
                                                    memberuserids = matteridname + token;
                                                    AdminUserId = userId;
                                                }

                                                object rawfile = new
                                                {
                                                    Accesstoken = "mykase123456789abcdef",
                                                    Email = email,
                                                    Memberuserid = memberuserids,
                                                    Password = "MykaSe_PasSsword",
                                                    Mobile = mobile,
                                                    Dispname = dispName,
                                                    Countryname = country,
                                                    StateName = state,
                                                    Subscriptionstart = SubsStartDate,
                                                    Subscriptionend = SubscriptionEndDate,
                                                    Userid = AdminUserId, //"Mykase_" + loggedInUserIdDetail
                                                    RegistrationType = 1,
                                                    RoleId= RoleId
                                                };
                                                addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
                                                string builders = JsonConvert.SerializeObject(rawfile);
                                                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                                                //string resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/InsertUserMappingAndAddUser"), "POST", builders);
                                                string resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/FirmMappingAndAddUser"), "POST", builders);
                                            }

                                        }
                                        catch (Exception ex)
                                        {

                                        }

                                        try
                                        {
                                            CommomUtility obj1 = new CommomUtility();
                                            obj1.SendEmail(fromemail, Email.EmailId, "", AssignmentSubmittedMailSubject, AssignmentSubmittedMailBody1);
                                        }
                                        catch (Exception ex)
                                        {

                                        }
                                    }
                                }
                                transaction.Commit();
                            }
                            catch (Exception et)
                            {
                                transaction.Rollback();
                                return Ok(et.Message);
                            }
                        }
                    }

                    else
                    {
                        return Ok("user exceed limit");
                    }
                }
                else
                {
                    return Ok("invalid user license");
                }
                return Ok();
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }

        }

