        }

        /// <summary>
        /// Insert row-by-row parent chain into UserParentChain table
        /// Each ancestor gets its own row: (UserId, AncestorId, Distance)
        /// </summary>
        private void InsertUserParentChain(LawPracticeEntities db, string userId, string parentId)
        {
            if (string.IsNullOrEmpty(userId) || string.IsNullOrEmpty(parentId))
                return;

            string currentParentId = parentId;
            int distance = 1;
            int safety = 0;

            while (!string.IsNullOrEmpty(currentParentId) && safety < 10)
            {
                db.Database.ExecuteSqlCommand(
                    @"IF NOT EXISTS (SELECT 1 FROM UserParentChain WHERE UserId = @p0 AND AncestorUserId = @p1)
                      INSERT INTO UserParentChain (UserId, AncestorUserId, Distance) VALUES (@p0, @p1, @p2)",
                    userId, currentParentId, distance);

                // Get next ancestor
                var nextParent = db.Database.SqlQuery<string>(
                    @"SELECT CAST(ParentUserId AS NVARCHAR(100)) 
                      FROM FirmUsers 
                      WHERE CAST(Id AS NVARCHAR(100)) = @p0",
                    currentParentId).FirstOrDefault();

                currentParentId = (!string.IsNullOrEmpty(nextParent)) ? nextParent : null;
                distance++;
                safety++;
            }
        }

