        /// <summary>
        /// Reset User Password
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult ResetUserPassword()
        {
            try
            {
                var db = new LawPracticeEntities();
                FirmUser obj = new FirmUser();
                obj.Password = QueryAES.GetHashedCode(QueryAES.UrlDecode(HttpContext.Current.Request.Form["newpass"]));
                obj.Password = obj.Password.Replace("\n", "");
                var tokenuserid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(QueryAES.UrlDecode(HttpContext.Current.Request.Form["tokenid"])));
                var strdetail = db.Usp_UpdatePassword(LoggedInUser.FirmId.ToString(), tokenuserid, obj.Password.ToString());
                try
                {
                    var dataac = Notification.SaveNotifications("PasswordChange", null, LoggedInUser.FirmId.ToString(), tokenuserid, tokenuserid, null);
                    // SendClientLogin mail
                    var useremail = db.usp_GetUserDetailByUserID(LoggedInUser.FirmId.ToString(), tokenuserid).FirstOrDefault();
                    if (useremail.EmailId != null)
                    {
                        var strbody = "";
                        strbody += "Dear " + useremail.Name + ",<br/><br/>";
                        var creatoremail = db.usp_GetUserDetailByUserID(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
                        strbody += "Your password has been changed by " + creatoremail.Name;
                        strbody += "<br/><br/>Your login credentials to access myKase:";
                        strbody += "<br/>UserName: " + useremail.UserName;
                        strbody += "<br/>New Password: " + QueryAES.UrlDecode(HttpContext.Current.Request.Form["newpass"] + "</br>");
                        string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                        var strsubject = "Notification from myKase- Password changed";
                        string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["basicmailtemplate"].ToString();
                        AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#CONTENT#", strbody);
                        try
                        {
                            CommomUtility objmail = new CommomUtility();
                            objmail.SendEmail(fromemail, useremail.EmailId, "", strsubject, AssignmentSubmittedMailBody);
                        }
                        catch (Exception ex)
                        {
                        }
                    }
                }
                catch (Exception)
                {
                }
                var param = controllername + ">ResetUserPassword>ResetUserPassword>param=" + obj.Password + "@" + obj.UserName + "@" + LoggedInUser.FirmId.ToString() + "@" + tokenuserid;
                return Ok(strdetail);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.ChangePassowrd), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.ChangePassowrd), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }

