        /// <summary>
        /// Add User Email Details
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult AddUserEmailDetails()
        {
            var logopath = "";
            try
            {
                var httpRequest = HttpContext.Current.Request;
                if (httpRequest.Files.Count > 0)
                {
                    var docfiles = new List<string>();
                    string folderPath = HttpContext.Current.Server.MapPath("~/UserMailLogo/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/");
                    //Check whether Directory (Folder) exists.
                    if (!Directory.Exists(folderPath))
                    {
                        //If Directory (Folder) does not exists. Create it.
                        Directory.CreateDirectory(folderPath);
                    }
                    for (int i = 0; i < httpRequest.Files.Count; i++)
                    {
                        var postedFile = httpRequest.Files[i];
                        var fileName = Path.GetFileNameWithoutExtension(postedFile.FileName);
                        var fileext = Path.GetExtension(postedFile.FileName);
                        fileName = fileName.Replace(" ", "");
                        var fileName1 = fileName + randomno() + fileext;
                        var filePath = folderPath + Path.GetFileName(fileName1); //HttpContext.Current.Server.MapPath(+ postedFile.FileName);
                        var fileextchk = Path.GetExtension(postedFile.FileName);
                        var is_valid = SaveCommonModulesDocument.chkValidExtension(fileextchk);
                        postedFile.SaveAs(filePath);
                        logopath = WebConfigurationManager.AppSettings["SiteUrl"] + "UserMailLogo/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/" + fileName1;
                    }
                }
                else
                {
                    logopath = QueryAES.UrlDecode(HttpContext.Current.Request.Form["filepath"]);
                }
                string strusername = WebConfigurationManager.AppSettings["matteridname"];
                var uname = QueryAES.UrlDecode(HttpContext.Current.Request.Form["name"]);
                var uorgnisation = QueryAES.UrlDecode(HttpContext.Current.Request.Form["orgnisation"]);
                var ureplyemail = QueryAES.UrlDecode(HttpContext.Current.Request.Form["replyemail"]);
                var ualertfor = QueryAES.UrlDecode(HttpContext.Current.Request.Form["alertfor"]);
                var usignatureemail = QueryAES.UrlDecode(HttpContext.Current.Request.Form["signatureemail"]);
                var usignaturemobile = QueryAES.UrlDecode(HttpContext.Current.Request.Form["signaturemobile"]);
                var usignaturelogo = logopath;
                var apiUrl = ConfigurationManager.AppSettings["savetocasewatchurl"];
                //add login data
                var addfClient = new WebClient();
                object rawfile = new
                {
                    accesstoken = "mykase123456789abcdef",
                    userid = strusername + LoggedInUser.UserId.ToString(),
                    name = uname,
                    orgnisation = uorgnisation,
                    replyemail = ureplyemail,
                    alertfor = ualertfor,
                    signatureemail = usignatureemail,
                    signaturemobile = usignaturemobile,
                    signaturelogo = usignaturelogo,
                };
                addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
                string builders = JsonConvert.SerializeObject(rawfile);
                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                var resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/AddUserMailDetail"), "POST", builders);
                dynamic data = JObject.Parse(resid);
                string status = data.Status;
                string Message = data.Message;
                string dataval = data.data;
                if (status.ToLower().ToString() == "true")
                {
                    //insert into map emailcaseatchuserdta
                    var cnt = db1.usp_SaveCaseWatchUserMailMap(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), strusername + LoggedInUser.UserId.ToString(), uorgnisation, ureplyemail, ualertfor, usignatureemail, usignaturemobile, usignaturelogo, uname);
                    return Ok(1);
                }
                else
                {
                    return Ok(0);
                }
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Contact), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Contact), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
