        /// <summary>
        /// Bind Email SignatureDetails
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult BindEmailSignatureDetails()
        {
            var logopath = "";
            try
            {
                string strusername = WebConfigurationManager.AppSettings["matteridname"];
                var apiUrl = ConfigurationManager.AppSettings["savetocasewatchurl"];
                //add login data
                var addfClient = new WebClient();
                object rawfile = new
                {
                    accesstoken = "mykase123456789abcdef",
                    userid = strusername + LoggedInUser.UserId.ToString(),
                };
                addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
                string builders = JsonConvert.SerializeObject(rawfile);
                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                var resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/UserMailDetail"), "POST", builders);
                JObject jObject = JObject.Parse(resid);
                dynamic data1 = jObject["data"];
                List<EmailSignature> EmailSignatures = new List<EmailSignature>();
                for (int i = 0; i < data1.Count; i++)
                {
                    dynamic data = JObject.Parse(resid);
                    string status = data.Status;
                    string Message = data.Message;
                    string Id = data.data[i].Id;
                    string vUsername = data.data[i].vUsername;
                    string vName = data.data[i].vName;
                    string vOrgnisationname = data.data[i].vOrgnisationname;
                    string ReplyEmail = data.data[i].ReplyEmail;
                    string AlertsFor = data.data[i].AlertsFor;
                    string dEntry = data.data[i].dEntry;
                    string dUpdated = data.data[i].dUpdated;
                    string SignatureEmail = data.data[i].SignatureEmail;
                    string SignatureMobile = data.data[i].SignatureMobile;
                    string SignatureLogo = data.data[i].SignatureLogo;
                    // Add parts to the list.
                    EmailSignatures.Add(new EmailSignature { Id = Convert.ToInt32(Id), vUsername = vUsername, vName = vName, vOrgnisationname = vOrgnisationname, ReplyEmail = ReplyEmail, AlertsFor = AlertsFor, dEntry = dEntry, dUpdated = dUpdated, SignatureEmail = SignatureEmail, SignatureMobile = SignatureMobile, SignatureLogo = SignatureLogo });
                }
                return Ok(EmailSignatures);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Contact), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Contact), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok(0);
            }
        }

