                var members = db.usp_getassignuserbyCommunicationId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), commuid).ToList();
                if (members != null)
                {
                    // mapuser and send email
                    string[] values = "".TrimStart(',').TrimEnd(',').Split(',');
