                        var subject = data.SubjectName.ToString();
                        if (!String.IsNullOrEmpty(valuesmember))
                        {
                            //notification
                            try
                            {
                                if (valuesmember.ToString() != "")
                                {
                                    var dataa = Notification.SaveNotifications("SentCommunication", null, firmid, userid, valuesmember.ToString(), caseid, caseid);
                                }
                            }
                            catch
                            {
                            }
                            //send email if success
                            try
                            {
                                if (valuesmember != "")
                                {
                                    var getemail = db.usp_GetEmailByUserId(LoggedInUser.FirmId.ToString(), valuesmember).FirstOrDefault();
                                    if (getemail != null)
                                    {
                                        string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                                        //send email to user
                                        string strsubject = "", strbody = "";
                                        var getusername2 = db.usp_GetUserNameById(LoggedInUser.FirmId.ToString(), valuesmember.ToString()).FirstOrDefault();
                                        if (getusername2 != null)
                                        {
                                            var msgusernames2 = getusername2.ToString();
                                            strbody += "Dear " + msgusernames2 + ",<br><br>";
                                        }
                                        strbody += "Greetings from myKase!<br><br>";
                                        var getusername = db.usp_GetUserNameById(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
                                        if (getusername != null)
                                        {
                                            var msgusernames = getusername.ToString();//QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(getusername.ToString()));
                                            strbody += "You are receiving the communication for the below mentioned matter from " + msgusernames + "<br><br>";
                                        }
                                        strbody += "Details are as follows:<br><br>";
                                        strbody += "Date/Time :" + DateTime.Now.ToString("dd-MMM-yyyy hh:mm:ss") + "<br><br>";
                                        if (caseid != null)
                                        {
                                            var getcase = db.usp_GetCaseNameById(LoggedInUser.FirmId.ToString(), caseid.ToString()).FirstOrDefault();
                                            if (getcase != null)
                                            {
                                                string msgcase = getcase;
                                                strbody += "Matter Name:" + msgcase + "<br><br>";
                                                strsubject = "myKase Notification- Re:Communication on matter " + msgcase;
                                            }

                                        }
                                        if (!String.IsNullOrEmpty(subject))
                                        {
                                            strbody += "Subject:" + subject + "<br><br>";
                                        }
                                        strbody += "Communication Brief :" + details + "<br><br>";
                                        if (!String.IsNullOrEmpty(sendemailpostedFiledata))
                                        {
                                            strbody += " Attachment: Yes<br><br>";
                                        }
                                        else
                                        {
                                            strbody += " Attachment: No<br><br>";
                                        }
                                        string SiteUrl = WebConfigurationManager.AppSettings["SiteUrl"].ToString();
                                        strbody += "Please <a href='" + SiteUrl + "' target='_blank'>click here</a> to reply.<br><br>";
                                        try
                                        {
                                            string attchment = sendemailpostedFiledata;
                                            if (attchment != null)
                                            {
                                                attchment = attchment.Replace("|", ",");
                                            }
                                            string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["basicmailtemplate"].ToString();
                                            AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#CONTENT#", strbody);
                                            CommomUtility objmail = new CommomUtility();
                                            objmail.SendEmail(fromemail, getemail.EmailId, "", strsubject, AssignmentSubmittedMailBody, attchment);
                                        }
                                        catch (Exception ex)
                                        {
                                        }
                                    }
                                }
                            }
                            catch (Exception ex)
                            {
                            }
                        }
                    }
                }
                //remove temp attachment
                try
                {
                    var attchment = sendemailpostedFiledata;
                    attchment = attchment.Replace("|", ",");
                    if (attchment.ToString().Trim() != "")
                    {
                        string[] CCattach = attchment.Split(',');
                        foreach (string ccattached in CCattach)
                        {
                            if (!string.IsNullOrEmpty(ccattached))
                            {
                                if (File.Exists(ccattached))
                                {
                                    // AttachmentPath1 = attached;
                                    System.IO.File.Delete(ccattached);
                                }
                                else
                                {
                                    attchment = "";
                                }
                            }
                        }
                    }
                }
                catch (Exception er)
                {
                }
                return Ok(new { Result = insertdata, InfectFiles = InfectedFilesResult });
            }
            catch (Exception ed)
            {
                return Ok(ed.Message);
            }
        }

