        /// <summary>
        /// Load Multiple Address
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult LoadMultipleAddress()
        {
            var data = "";
            try
            {
                int pagenum = Convert.ToInt32(QueryAES.UrlDecode(HttpContext.Current.Request.Form["pagenum"]));
                int pagesize = Convert.ToInt32(QueryAES.UrlDecode(HttpContext.Current.Request.Form["pagesize"]));
                var type = QueryAES.UrlDecode(HttpContext.Current.Request.Form["type"]);
                var db = new LawPracticeEntities();
                var client = QueryAES.UrlDecode(HttpContext.Current.Request.Form["client"]);
                if (string.IsNullOrEmpty(client))
                {
                    client = "";
                }
                var contact = QueryAES.UrlDecode(HttpContext.Current.Request.Form["contact"]);
                if (string.IsNullOrEmpty(contact))
                {
                    contact = "";
                }
                else
                {
                    try
                    {
                        contact = contact.Replace(" ", "+");
                        contact = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(contact));
                    }
                    catch
                    {

                    }
                }
                StringBuilder sb = new StringBuilder();
                List<usp_GetMultipleAddressTable_Result> list = new List<usp_GetMultipleAddressTable_Result>();
                list = db.usp_GetMultipleAddressTable(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), pagenum, pagesize, client, contact, type).ToList();
                foreach (var datas in list.ToList())
                {
                    usp_GetMultipleAddressTable_Result newItem = new usp_GetMultipleAddressTable_Result();
                    if (string.IsNullOrEmpty(datas.ClientId))
                    {
                        newItem.ContactId = Convert.ToBase64String(QueryAES.EncryptAes(datas.ContactId.ToString()));
                        list[list.IndexOf(datas)].ContactId = newItem.ContactId;
                    }
                }
                data = JsonConvert.SerializeObject(list);
                return Ok(data);
            }
            catch (Exception ex)
            {
                return Ok();
            }
        }

