            try
            {
                string Id = QueryAES.UrlDecode(HttpContext.Current.Request.Form["Id"]);
                var db = new LawPracticeEntities();
                StringBuilder sb = new StringBuilder();
                List<usp_UpdateMultipleAddress_Result> list = new List<usp_UpdateMultipleAddress_Result>();
                list = db.usp_UpdateMultipleAddress(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), Id).ToList();
                foreach (var datas in list.ToList())
                {
                    usp_UpdateMultipleAddress_Result newItem = new usp_UpdateMultipleAddress_Result();
                    if (!string.IsNullOrEmpty(datas.ContactId))
                    {
                        newItem.ContactId = Convert.ToBase64String(QueryAES.EncryptAes(datas.ContactId.ToString()));
                        list[list.IndexOf(datas)].ContactId = newItem.ContactId;
                    }
                }
                data = JsonConvert.SerializeObject(list);
                return Ok(data);
            }
            catch (Exception ex)
            {
                return Ok();
            }
        }

