        /// <summary>
        /// Load All Matter By FirmId
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization()]
        [System.Web.Mvc.HttpPost]
        public IHttpActionResult LoadAllMatterByFirmId()
        {
            try
            {
                string pageno = QueryAES.UrlDecode(HttpContext.Current.Request.Form["Pageno"]);
                string clientid = QueryAES.UrlDecode(HttpContext.Current.Request.Form["clientid"]);
                string companyids = QueryAES.UrlDecode(HttpContext.Current.Request.Form["companyids"]);
                if (pageno == "null" || pageno == "" || pageno == "undefined")
                    pageno = "1";
                if (clientid == "null" || clientid == null || clientid == "undefined" || clientid == "")
                    clientid = "00000000-0000-0000-0000-000000000000";
                if (companyids == "null" || companyids == null || companyids == "undefined" || companyids == "")
                    companyids = "00000000-0000-0000-0000-000000000000";

                var cacheKey = "LoadAllMatterByFirmId_" + LoggedInUser.FirmId.ToString() + "_" + LoggedInUser.UserId.ToString() + "_" + pageno + "_" + clientid + "_" + companyids;
                var cached = HttpContext.Current.Cache[cacheKey];
                if (cached != null)
                    return Ok(cached);

                var db = new LawPracticeEntities();
                var cmatter = db.Usp_GetAllMatterListByFirmId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), Convert.ToInt32(pageno), clientid, companyids).ToList();
                HttpContext.Current.Cache.Insert(cacheKey, cmatter, null, DateTime.Now.AddMinutes(5), TimeSpan.Zero);
                return Ok(cmatter);
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Ok();
            }
        }
